// DevTool Widget Component
interface DevToolWidgetProps {
    onClose: () => void;
    settings: UiSettings;
    updateSetting: (key: keyof UiSettings, val: number) => void;
    onReset: () => void;
    uiConfig: any;
}

const DevToolWidget = ({ onClose, settings, updateSetting, onReset, uiConfig }: DevToolWidgetProps) => {
    const settingKeys = Object.keys(settings) as (keyof UiSettings)[];
    const [currentIndex, setCurrentIndex] = useState(0);
    const currentKey = settingKeys[currentIndex];

    const getSettingRange = (key: keyof UiSettings) => {
        if (key.includes('Height') || key.includes('Width') || key.includes('Size') || key.includes('Gap') || key.includes('Padding')) {
            if (key === 'maxWidth') return { min: 300, max: 1200 };
            if (key === 'borderRadiusFull') return { min: 0, max: 999 };
            return { min: 0, max: 200 };
        }
        if (key.includes('opacity') || key.includes('Intensity') || key.includes('activeScale')) return { min: 0, max: 100 };
        if (key.includes('Weight')) return { min: 100, max: 900 };
        if (key.includes('lineHeight')) return { min: 80, max: 250 };
        if (key.includes('animation')) return { min: 0, max: 1000 };
        return { min: 0, max: 100 };
    };

    const range = getSettingRange(currentKey);

    return (
        <div className="fixed bottom-0 left-0 right-0 z-[200] bg-custom-950 border-t border-custom-900 shadow-[0_-10px_40px_rgba(0,0,0,0.5)] animate-fade-in">
             <div className="max-w-xl mx-auto p-4 flex flex-col gap-4">

                 <div className="flex justify-between items-center mb-1">
                     <div className="flex items-center gap-2 text-custom-500">
                         <Wrench className="w-4 h-4" />
                         <span className="text-xs font-bold font-mono uppercase tracking-widest">DEV_TOOLS</span>
                     </div>
                     <div className="flex gap-2">
                        <button onClick={onReset} className="px-3 py-1 bg-red-900/20 text-red-500 text-xs font-bold uppercase hover:bg-red-900/40 rounded transition-colors">Reset</button>
                        <button onClick={onClose} className="px-3 py-1 bg-custom-900 text-custom-400 text-xs font-bold uppercase hover:text-white rounded transition-colors">Close</button>
                     </div>
                 </div>

                 {/* Slider 1: Parameter Selection */}
                 <div>
                    <div className="flex justify-between items-baseline mb-2">
                        <span className="text-white font-bold font-mono text-sm uppercase tracking-wider">{RUSSIAN_LABELS[currentKey]}</span>
                        <span className="text-custom-600 text-[10px] font-mono">{currentIndex + 1} / {settingKeys.length}</span>
                    </div>
                    <input 
                        type="range"
                        min="0"
                        max={settingKeys.length - 1}
                        value={currentIndex}
                        onChange={(e) => setCurrentIndex(parseInt(e.target.value))}
                        className="w-full h-1 bg-custom-900 rounded-lg appearance-none cursor-pointer accent-blue-500"
                    />
                 </div>

                 {/* Slider 2: Value Adjustment */}
                 <div>
                     <div className="flex justify-between items-baseline mb-2">
                        <span className="text-custom-400 text-xs font-bold uppercase tracking-widest">VALUE</span>
                        <span className="text-blue-400 font-mono text-lg font-bold">{settings[currentKey]}</span>
                     </div>
                     <input 
                        type="range"
                        min={range.min}
                        max={range.max}
                        value={settings[currentKey]}
                        onChange={(e) => updateSetting(currentKey, parseInt(e.target.value))}
                        className="w-full h-6 bg-custom-900 rounded appearance-none cursor-pointer accent-white"
                     />
                 </div>

                 {/* Description Area */}
                 <div className="bg-custom-900/30 p-3 rounded border border-custom-900/50 min-h-[60px]">
                     <p className="text-custom-400 text-xs leading-relaxed">
                         {PARAMETER_DESCRIPTIONS[currentKey]}
                     </p>
                 </div>
             </div>
        </div>
    );
};

