export default function App() {
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [previousView, setPreviousView] = useState<ViewState>('DASHBOARD');
  const [formulas, setFormulas] = useState<Formula[]>([]);
  const [activeFormula, setActiveFormula] = useState<Formula | null>(null);
  const [editingFormula, setEditingFormula] = useState<Formula | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isGridView, setIsGridView] = useState(true);
  const [showHelp, setShowHelp] = useState(false);
  const [showDevTools, setShowDevTools] = useState(false);
  const [showJsonImport, setShowJsonImport] = useState(false);
  const [startEditorWithAi, setStartEditorWithAi] = useState(false);

  // Customization State
  const [theme, setTheme] = useState('custom'); // Always custom to use dynamic styles
  const [rgb, setRgb] = useState(DEFAULT_RGB);
  const [uiSettings, setUiSettings] = useState<UiSettings>(DEFAULT_UI_SETTINGS);

  // Generate CSS for the current RGB values
  const themeCss = generateThemeCss(rgb.r, rgb.g, rgb.b, uiSettings);

  // Construct Dynamic UI Configuration from Settings
  const uiConfig = {
      headerClassName: `text-[${uiSettings.headerFontSize}px] font-[${uiSettings.weightHeader}] tracking-[${uiSettings.letterSpacingHeader}px]`,
      bodyClassName: `text-[${uiSettings.bodyFontSize}px] font-[${uiSettings.weightBody}] tracking-[${uiSettings.letterSpacingBody}px]`,
      iconClassName: `w-[${uiSettings.iconSize}px] h-[${uiSettings.iconSize}px]`,

      headerHeightClass: `h-[${uiSettings.headerHeight}px]`,
      rowHeightClass: `min-h-[${uiSettings.rowHeight}px]`,

      inputFontSize: `text-[${uiSettings.inputFontSize}px] font-[${uiSettings.weightInput}]`,
      resultFontSize: `text-[${uiSettings.resultFontSize}px]`,

      // Complex Padding classes using CSS-in-JS logic would be better, but sticking to Tailwind-ish injection
      // We are actually mostly relying on the injected classes/styles now, but providing fallback/specifics
      paddingClass: `px-[${uiSettings.screenPaddingX}px] py-[${uiSettings.screenPaddingY}px]`,
      gapClass: `gap-[${uiSettings.elementGapX}px]`,

      // Passing raw values for components that need them inline
      iconSize: uiSettings.iconSize,
  };

  // State for delete confirmation
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  // Long press refs
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isLongPress = useRef(false);

  useEffect(() => {
    const saved = localStorage.getItem('customcalc_formulas');
    if (saved) {
      try {
        setFormulas(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load formulas", e);
      }
    } else {
        setShowHelp(true);
    }

    // Load Settings
    const savedSettings = localStorage.getItem('customcalc_settings_v2');
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            if (parsed.uiSettings) setUiSettings({...DEFAULT_UI_SETTINGS, ...parsed.uiSettings});
            if (parsed.rgb) setRgb(parsed.rgb);
        } catch(e) {}
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('customcalc_formulas', JSON.stringify(formulas));
  }, [formulas]);

  useEffect(() => {
      localStorage.setItem('customcalc_settings_v2', JSON.stringify({
          uiSettings,
          rgb
      }));
  }, [uiSettings, rgb]);

  useEffect(() => {
      if (deleteConfirmId) {
          const timer = setTimeout(() => setDeleteConfirmId(null), 3000);
          return () => clearTimeout(timer);
      }
  }, [deleteConfirmId]);

  const handleResetSettings = () => {
      if(window.confirm("Вы уверены, что хотите сбросить ВСЕ визуальные настройки по умолчанию?")) {
          localStorage.removeItem('customcalc_settings_v2');
          setUiSettings({...DEFAULT_UI_SETTINGS});
          setRgb({...DEFAULT_RGB});
      }
  }

  const handleUpdateSetting = (key: keyof UiSettings, val: number) => {
      setUiSettings(prev => ({...prev, [key]: val}));
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(formulas, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const date = new Date().toISOString().slice(0, 10);
    const exportFileDefaultName = `customcalc_backup_${date}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const handleImportData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileReader = new FileReader();
    if (e.target.files && e.target.files.length > 0) {
        fileReader.readAsText(e.target.files[0], "UTF-8");
        fileReader.onload = (event) => {
            try {
                if (event.target?.result) {
                    const parsed = JSON.parse(event.target.result as string);
                    if (Array.isArray(parsed)) {
                        if (window.confirm("Overwrite current data?")) {
                            setFormulas(parsed);
                            setShowHelp(false);
                        }
                    } else {
                        alert("Invalid file format");
                    }
                }
            } catch (error) {
                alert('Error reading file');
            }
        };
        e.target.value = '';
    }
  };

  const handleSaveFormula = (formula: Formula) => {
    const isNew = !formulas.some(f => f.id === formula.id);
    setFormulas(prev => {
       const exists = prev.find(f => f.id === formula.id);
       if (exists) {
         return prev.map(f => f.id === formula.id ? formula : f);
       }
       return [formula, ...prev];
    });

    if (isNew) {
        setActiveFormula(formula);
        setView('RUNNER');
    } else {
        if (activeFormula && activeFormula.id === formula.id) {
            setActiveFormula(formula);
            setView('RUNNER');
        } else {
            setView(previousView === 'RUNNER' ? 'RUNNER' : 'DASHBOARD');
        }
    }
    setEditingFormula(null);
  };

  const handleDeleteFormula = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (deleteConfirmId === id) {
        setFormulas(prev => prev.filter(f => f.id !== id));
        setDeleteConfirmId(null);
        localStorage.removeItem(`calc_inputs_${id}`);
    } else {
        setDeleteConfirmId(id);
    }
  };

  const handleDeleteFromRunner = () => {
      if (activeFormula) {
          setFormulas(prev => prev.filter(f => f.id !== activeFormula.id));
          localStorage.removeItem(`calc_inputs_${activeFormula.id}`);
          setActiveFormula(null);
          setView('DASHBOARD');
      }
  };

  const handleEditFormula = (e: React.MouseEvent, formula: Formula) => {
    e.stopPropagation();
    setEditingFormula(formula);
    setActiveFormula(null); 
    setStartEditorWithAi(false);
    setPreviousView('DASHBOARD');
    setView('EDITOR');
  };

  const handleCreateNew = () => {
    setEditingFormula(null);
    setActiveFormula(null);
    setStartEditorWithAi(false);
    setPreviousView('DASHBOARD');
    setView('EDITOR');
  };

  const handleCreateWithAi = () => {
    setEditingFormula(null);
    setActiveFormula(null);
    setStartEditorWithAi(true);
    setPreviousView('DASHBOARD');
    setView('EDITOR');
  }

  const handleOpenFormula = (formula: Formula) => {
    if (deleteConfirmId === formula.id) {
        setDeleteConfirmId(null);
        return;
    }
    setActiveFormula(formula);
    setView('RUNNER');
  };

  const handleEditFromRunner = () => {
    if (activeFormula) {
        setEditingFormula(activeFormula);
        setStartEditorWithAi(false);
        setPreviousView('RUNNER');
        setView('EDITOR');
    }
  };

  // Long Press Handlers
  const handleButtonDown = () => {
      isLongPress.current = false;
      timerRef.current = setTimeout(() => {
          isLongPress.current = true;
          if (navigator.vibrate) navigator.vibrate(uiSettings.longPressDelay / 10);
          setShowJsonImport(true);
      }, uiSettings.longPressDelay);
  };

  const handleButtonUp = () => {
      if (timerRef.current) {
          clearTimeout(timerRef.current);
          timerRef.current = null;
      }
      if (!isLongPress.current && !showJsonImport) {
          handleCreateNew();
      }
  };

  const handleJsonImportAction = (jsonString: string) => {
      try {
          const result = cleanAndParseJSON(jsonString);
          const newFormula: Formula = {
              id: Date.now().toString(),
              title: result.title || "Untitled",
              description: result.explanation || "",
              expression: result.expression,
              resultName: result.resultName || "Result",
              resultUnit: result.resultUnit || "",
              variables: result.variables.map((v: any, idx: number) => ({
                  id: Date.now().toString() + idx,
                  name: v.name,
                  symbol: v.symbol,
                  unit: v.unit
              })),
              color: `bg-custom-950`, // Always custom
              icon: 'calculator',
              aiJson: jsonString
          };

          // IMMEDIATE SAVE AND RUN
          handleSaveFormula(newFormula);
          setShowJsonImport(false);
      } catch (e) {
          alert("JSON Parse Failed");
      }
  };

  const filteredFormulas = formulas.filter(f => 
    f.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    f.description.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className={`min-h-screen bg-custom-950 text-custom-300 font-sans selection:bg-blue-500/30 flex flex-col items-center`}>
      <style>{themeCss}</style>

      {/* Centered container with maxWidth setting */}
      <div className="w-full flex flex-col h-full shadow-2xl relative" style={{ maxWidth: `${uiSettings.maxWidth}px` }}>

      {showHelp && (
        <HelpModal 
            onClose={() => setShowHelp(false)} 
            onExport={handleExportData}
            onImport={handleImportData}

            rgb={rgb}
            setRgb={setRgb}
            settings={uiSettings}
            updateSetting={handleUpdateSetting}
            onReset={handleResetSettings}

            uiConfig={uiConfig} 
        />
      )}

      {showDevTools && (
          <DevToolWidget 
            onClose={() => setShowDevTools(false)}
            settings={uiSettings}
            updateSetting={handleUpdateSetting}
            onReset={handleResetSettings}
            uiConfig={uiConfig}
          />
      )}

      {showJsonImport && (
        <JsonImportModal 
            onClose={() => setShowJsonImport(false)}
            onImport={handleJsonImportAction}
            uiConfig={uiConfig}
        />
      )}

      {view === 'DASHBOARD' && (
          <div className="flex flex-col h-screen overflow-hidden">
            {/* Header */}
            <div className={`bg-custom-950 px-4 py-0 shrink-0 sticky top-0 z-20 flex justify-between items-center ${uiConfig.headerHeightClass} border-b border-custom-900`}>
                 <button onClick={() => setShowDevTools(true)} className={`text-custom-600 hover:text-white transition-colors p-2`}>
                     <Wrench className={uiConfig.iconClassName} />
                 </button>
                 <h1 className={`${uiConfig.headerClassName} font-bold text-white flex items-center font-mono`}>
                    CCS<span className="text-blue-500">_</span>V2
                 </h1>
                 <button onClick={() => setShowHelp(true)} className={`text-custom-600 hover:text-white transition-colors p-2`}>
                    <Settings className={uiConfig.iconClassName} />
                 </button>
            </div>

            {/* Content Area */}
            <div className={`flex-1 overflow-y-auto pb-[${uiSettings.footerHeight}px] scroll-smooth`}>
                {formulas.length === 0 ? (
                    <div className={`flex flex-col items-center justify-center h-[60vh] text-custom-600`}>
                        <div className="mb-4 font-mono text-8xl opacity-10 font-bold">00</div>
                        <h3 className={`text-white font-bold ${uiConfig.headerClassName} mb-2 font-mono uppercase tracking-widest`}>System_Empty</h3>
                        <button 
                            onPointerDown={handleButtonDown}
                            onPointerUp={handleButtonUp}
                            onPointerLeave={() => { if(timerRef.current) clearTimeout(timerRef.current); }}
                            className={`text-blue-500 hover:text-blue-400 ${uiConfig.bodyClassName} font-bold font-mono tracking-widest mt-8 border-b border-blue-500/30 pb-1`}
                        >
                            INITIATE_NEW
                        </button>
                    </div>
                ) : (
                    <div 
                        className={isGridView ? `grid grid-cols-2 bg-custom-900 border-b border-custom-900` : `flex flex-col divide-y divide-custom-900`}
                        style={{ gap: isGridView ? `${uiSettings.gridGap}px` : `${uiSettings.listGap}px` }}
                    >
                        {filteredFormulas.map(formula => {
                           const isDeleteArmed = deleteConfirmId === formula.id;

                           if (isGridView) {
                               return (
                                 <div 
                                    key={formula.id}
                                    onClick={() => handleOpenFormula(formula)}
                                    className={`group relative bg-card-base hover:bg-custom-900 cursor-pointer flex flex-col justify-between transition-colors ${isDeleteArmed ? 'bg-red-900/10' : ''}`}
                                    style={{ 
                                        minHeight: `${uiSettings.gridRowHeight}px`,
                                        padding: `${uiSettings.cardPaddingY}px ${uiSettings.cardPaddingX}px`
                                    }}
                                 >
                                    <div className="flex justify-between items-start w-full relative">
                                        <h3 className={`${uiConfig.bodyClassName} font-bold text-white leading-tight mb-1 line-clamp-2 font-mono uppercase tracking-wide`}>{formula.title}</h3>

                                        <div className={`absolute -top-3 -right-3 flex flex-col gap-0 transition-opacity ${isDeleteArmed ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                                            {!isDeleteArmed && (
                                                <button 
                                                    onClick={(e) => handleEditFormula(e, formula)} 
                                                    className={`p-2 text-custom-600 hover:text-blue-400`}
                                                >
                                                    <Edit2 className={uiConfig.iconClassName}/>
                                                </button>
                                            )}
                                             <button 
                                                onClick={(e) => handleDeleteFormula(e, formula.id)} 
                                                className={`p-2 transition-all ${isDeleteArmed ? 'text-red-500' : `text-custom-600 hover:text-red-400`}`}
                                            >
                                                <Trash2 className={uiConfig.iconClassName}/>
                                            </button>
                                        </div>
                                    </div>

                                    <div className="mt-1">
                                        <p className={`${uiConfig.bodyClassName} opacity-60 text-custom-600 font-mono truncate`}>{formula.expression}</p>
                                    </div>
                                 </div>
                               );
                           } else {
                               return (
                                 <div 
                                    key={formula.id}
                                    onClick={() => handleOpenFormula(formula)}
                                    className={`group relative bg-card-base hover:bg-custom-900 cursor-pointer flex items-center transition-colors ${isDeleteArmed ? 'bg-red-900/10' : ''}`}
                                    style={{ 
                                        minHeight: `${uiSettings.rowHeight}px`,
                                        gap: `${uiSettings.elementGapX}px`,
                                        padding: `${uiSettings.cardPaddingY}px ${uiSettings.cardPaddingX}px`
                                    }}
                                 >
                                    <div className="flex-1 min-w-0 text-left">
                                        <h3 className={`${uiConfig.headerClassName} font-bold text-white leading-tight mb-1 truncate font-mono uppercase tracking-wide`}>
                                            {formula.title}
                                        </h3>
                                        <p className={`${uiConfig.bodyClassName} opacity-60 text-custom-600 truncate font-mono`}>
                                            {formula.expression}
                                        </p>
                                    </div>

                                    <div className={`flex items-center`} style={{ gap: `${uiSettings.elementGapX}px`}}>
                                        <button onClick={(e) => handleEditFormula(e, formula)} className={`text-custom-600 hover:text-blue-400`}><Edit2 className={uiConfig.iconClassName}/></button>
                                        <button 
                                            onClick={(e) => handleDeleteFormula(e, formula.id)} 
                                            className={`transition-all ${isDeleteArmed ? 'text-red-500' : `text-custom-600 hover:text-red-400`}`}
                                        >
                                            <Trash2 className={uiConfig.iconClassName}/>
                                        </button>
                                    </div>
                                 </div>
                               );
                           }
                        })}
                    </div>
                )}
            </div>

            {/* Bottom Controls Bar (Borderless) */}
            <div className={`bg-custom-950 border-t border-custom-900 p-0 fixed bottom-0 z-30 flex safe-area-pb`} 
                style={{ 
                    height: `${uiSettings.footerHeight}px`,
                    maxWidth: `${uiSettings.maxWidth}px`,
                    width: '100%'
                }}
            >
                 <button 
                    onClick={handleCreateWithAi}
                    className={`flex-1 flex items-center justify-center text-indigo-400 hover:text-white hover:bg-custom-900 transition-colors border-r border-custom-900`}
                 >
                     <Sparkles className={uiConfig.iconClassName} />
                 </button>

                 <div className={`relative flex-[3] flex items-center border-r border-custom-900`} style={{ height: `${uiSettings.searchBarHeight}px`, alignSelf: 'center' }}>
                    <input 
                      type="text" 
                      placeholder="SEARCH_DB" 
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className={`w-full h-full bg-transparent text-white ${uiConfig.bodyClassName} font-mono outline-none placeholder-custom-700 uppercase`}
                      style={{ paddingLeft: `${uiSettings.inputPaddingX}px`, paddingRight: `${uiSettings.inputPaddingX}px` }}
                    />
                    {searchQuery && (
                        <button 
                            onClick={() => setSearchQuery('')}
                            className={`absolute right-4 text-custom-600 hover:text-white`}
                        >
                            <X className={uiConfig.iconClassName} />
                        </button>
                    )}
                 </div>
                 <button 
                    onClick={() => setIsGridView(!isGridView)} 
                    className={`flex-1 flex items-center justify-center text-custom-500 hover:text-white hover:bg-custom-900 transition-colors border-r border-custom-900`}
                 >
                    {isGridView ? <List className={uiConfig.iconClassName}/> : <Grid className={uiConfig.iconClassName}/>}
                 </button>
                 <button 
                    onPointerDown={handleButtonDown}
                    onPointerUp={handleButtonUp}
                    onPointerLeave={() => { if(timerRef.current) clearTimeout(timerRef.current); }}
                    onContextMenu={(e) => e.preventDefault()}
                    className="flex-1 flex items-center justify-center bg-blue-600 text-white hover:bg-blue-500 transition-colors active:bg-blue-400 select-none touch-none"
                 >
                    <Plus className={uiConfig.iconClassName} />
                 </button>
            </div>
          </div>
        )}

        {view === 'EDITOR' && (
          <FormulaEditor 
            initialFormula={editingFormula}
            onSave={handleSaveFormula}
            onCancel={() => setView(previousView)} 
            startWithAi={startEditorWithAi}
            theme={theme}
            uiConfig={uiConfig}
            onOpenSettings={() => setShowHelp(true)}
            onOpenDevTools={() => setShowDevTools(true)}
          />
        )}

        {view === 'RUNNER' && activeFormula && (
          <FormulaRunner 
            formula={activeFormula}
            onBack={() => setView('DASHBOARD')}
            onEdit={handleEditFromRunner}
            onDelete={handleDeleteFromRunner}
            theme={theme}
            uiConfig={uiConfig}
            onOpenSettings={() => setShowHelp(true)}
            onOpenDevTools={() => setShowDevTools(true)}
          />
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, ArrowRightLeft, Info, RotateCcw, Edit2, Copy, Trash2, Keyboard, ChevronDown, Delete, X, Minus, Sliders, Settings, Wrench } from 'lucide-react';
import { Formula } from '../types';

interface FormulaRunnerProps {
  formula: Formula;
  onBack: () => void;
  onEdit: () => void;
  onDelete: () => void;
  theme: string;
  uiConfig: any;
  onOpenSettings: () => void;
  onOpenDevTools: () => void;
}

interface RangeConfig {
  min: string;
  max: string;
  enabled: boolean;
  step?: string;
  precision?: number;
}

export const FormulaRunner: React.FC<FormulaRunnerProps> = ({ formula, onBack, onEdit, onDelete, theme, uiConfig, onOpenSettings, onOpenDevTools }) => {
  // Inputs & Calculation State
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [result, setResult] = useState<number | string>('---');
  const [targetResult, setTargetResult] = useState<string>('');

  // UI State
  const [showInfo, setShowInfo] = useState(false);
  const [isDeleteArmed, setIsDeleteArmed] = useState(false);
  const [showKeyboard, setShowKeyboard] = useState(false);
  const [preferNativeKeyboard, setPreferNativeKeyboard] = useState(false);
  const [activeField, setActiveField] = useState<string | null>(null);

  // Slider / Range State
  const [rangeConfigs, setRangeConfigs] = useState<Record<string, RangeConfig>>({});
  const [activeRangeModalVar, setActiveRangeModalVar] = useState<string | null>(null);
  const [tempRange, setTempRange] = useState({ min: '', max: '' });
  const [activeModalInput, setActiveModalInput] = useState<'min' | 'max' | null>(null);

  // Long press logic refs
  const delTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isPressingRef = useRef(false);
  const labelPressTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Goal Seek State
  const [solvingVar, setSolvingVar] = useState<string>(formula.variables[0]?.symbol || '');
  const [isReverseMode, setIsReverseMode] = useState(false);

  // Load state from localStorage on mount
  useEffect(() => {
    // Load Inputs
    const savedInputs = localStorage.getItem(`calc_inputs_${formula.id}`);
    const initialInputs: Record<string, string> = {};

    if (savedInputs) {
        try {
            const parsed = JSON.parse(savedInputs);
            setInputs(parsed);
        } catch (e) {
            formula.variables.forEach(v => {
               initialInputs[v.symbol] = v.defaultValue !== undefined ? String(v.defaultValue) : '';
            });
            setInputs(initialInputs);
        }
    } else {
        formula.variables.forEach(v => {
           initialInputs[v.symbol] = v.defaultValue !== undefined ? String(v.defaultValue) : '';
        });
        setInputs(initialInputs);
    }

    // Load Range Configs
    const savedRanges = localStorage.getItem(`calc_ranges_${formula.id}`);
    if (savedRanges) {
        try {
            setRangeConfigs(JSON.parse(savedRanges));
        } catch (e) {
            console.error("Failed to parse saved ranges");
        }
    }
  }, [formula.id]);

  // Save inputs and ranges to localStorage
  useEffect(() => {
     if (Object.keys(inputs).length > 0) {
        localStorage.setItem(`calc_inputs_${formula.id}`, JSON.stringify(inputs));
     }
  }, [inputs, formula.id]);

  useEffect(() => {
      localStorage.setItem(`calc_ranges_${formula.id}`, JSON.stringify(rangeConfigs));
  }, [rangeConfigs, formula.id]);

  const calculateForward = (currentInputs: Record<string, string>) => {
    try {
      const calcInputs: Record<string, number> = {};
      Object.keys(currentInputs).forEach(k => {
          const valStr = currentInputs[k].replace(',', '.');
          const val = valStr === '' || valStr === '-' ? 0 : parseFloat(valStr);
          calcInputs[k] = isNaN(val) ? 0 : val;
      });

      const names = Object.keys(calcInputs);
      const values = Object.values(calcInputs);
      const func = new Function(...names, `return (${formula.expression});`);
      const res = func(...values);
      return isNaN(res) || !isFinite(res) ? 'Error' : res;
    } catch {
      return 'Error';
    }
  };

  useEffect(() => {
    if (!isReverseMode) {
        const res = calculateForward(inputs);
        setResult(typeof res === 'number' ? Math.round(res * 10000) / 10000 : res);
        if (typeof res === 'number') {
            const rounded = Math.round(res * 10000) / 10000;
            setTargetResult(String(rounded));
        } else {
            setTargetResult(String(res));
        }
    }
  }, [inputs, formula.expression, isReverseMode]);

  const solveForTarget = (target: number, varSymbol: string) => {
    let currentInputsNumeric: Record<string, number> = {};
    Object.keys(inputs).forEach(k => {
        const valStr = inputs[k].replace(',', '.');
        currentInputsNumeric[k] = (valStr === '' || valStr === '-') ? 0 : parseFloat(valStr);
        if (isNaN(currentInputsNumeric[k])) currentInputsNumeric[k] = 0;
    });

    let x0 = currentInputsNumeric[varSymbol] || 1; 
    let x1 = x0 + 0.1;
    const maxIter = 50;
    const tolerance = 0.0001;

    const calc = (val: number) => {
        const temp = { ...currentInputsNumeric, [varSymbol]: val };
        const names = Object.keys(temp);
        const values = Object.values(temp);
        try {
            const f = new Function(...names, `return (${formula.expression});`);
            return Number(f(...values));
        } catch { return 0; }
    };

    for (let i = 0; i < maxIter; i++) {
        const y0 = calc(x0);
        const y1 = calc(x1);

        if (Math.abs(y1 - target) < tolerance) {
            setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
            return;
        }
        if (Math.abs(y1 - y0) < 1e-9) {
            x1 = x1 + Math.random(); 
            continue;
        }
        const x_new = x1 - (y1 - target) * (x1 - x0) / (y1 - y0);
        x0 = x1;
        x1 = x_new;
    }
    setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
  };

  const handleTargetChange = (val: string) => {
    setTargetResult(val);
    const num = parseFloat(val.replace(',', '.'));
    if (!isNaN(num) && solvingVar && val.trim() !== '' && val !== '-') {
        setIsReverseMode(true);
        solveForTarget(num, solvingVar);
    }
  };

  const handleNativeInputChange = (id: string, val: string) => {
      let processedVal = val;
      if (id === 'target') {
          handleTargetChange(processedVal);
      } else {
          setInputs(prev => ({...prev, [id]: processedVal}));
          setIsReverseMode(false);

          // Auto-update slider MAX if enabled and value is not 0
          if (rangeConfigs[id]?.enabled) {
              const numVal = parseFloat(processedVal);
              if (!isNaN(numVal) && numVal !== 0 && processedVal !== '') {
                  setRangeConfigs(prev => ({
                      ...prev,
                      [id]: {
                          ...prev[id],
                          max: processedVal
                      }
                  }));
              }
          }
      }
  };

  const handleSliderChange = (id: string, val: string) => {
      setInputs(prev => ({...prev, [id]: val}));
      setIsReverseMode(false);
  };

  const handleFieldFocus = (fieldId: string) => {
      setActiveField(fieldId);
      if (fieldId === 'target') setIsReverseMode(true);

      // Do not show keyboard if slider is enabled for this field
      if (rangeConfigs[fieldId]?.enabled) {
          setShowKeyboard(false);
          return;
      }

      if (!preferNativeKeyboard) {
          setShowKeyboard(true);
      } else {
          setShowKeyboard(false);
      }
  };

  // --- Keyboard Logic (Virtual) ---
  const handleVirtualInput = (char: string) => {
      const processInput = (prev: string) => {
          if (char === 'CLEAR') return '';
          if (char === 'DEL') return prev.slice(0, -1);
          if (char === 'DONE') {
              handleDismissKeyboardPermanently();
              return prev;
          }
          if (char === '-') {
             if (prev.startsWith('-')) return prev.slice(1);
             return '-' + prev;
          }
          let newChar = char;
          if (newChar === ',') newChar = '.';
          if (newChar === '.') {
              if (prev.includes('.') || prev.includes(',')) return prev;
              if (prev === '') return '0.';
              return prev + '.';
          }
          if (prev === '0' && !isNaN(parseInt(newChar))) return '0.' + newChar;
          return prev + newChar;
      };

      // Modal Virtual Input Logic
      if (activeRangeModalVar && activeModalInput) {
          setTempRange(prev => ({
              ...prev,
              [activeModalInput]: processInput(prev[activeModalInput])
          }));
          return;
      }

      // Main Logic
      if (!activeField) return;
      if (activeField === 'target') {
          handleTargetChange(processInput(targetResult));
      } else {
          setInputs(prev => ({ ...prev, [activeField]: processInput(prev[activeField] || '') }));
          setIsReverseMode(false);

          // Slider Logic for Virtual Input
          if (rangeConfigs[activeField]?.enabled) {
             const newVal = processInput(inputs[activeField] || '');
             const numVal = parseFloat(newVal);
             if (!isNaN(numVal) && numVal !== 0 && newVal !== '') {
                 setRangeConfigs(prev => ({
                    ...prev,
                    [activeField]: { ...prev[activeField], max: newVal }
                 }));
             }
          }
      }
  };

  const handleDelDown = (e: React.PointerEvent) => {
    e.preventDefault(); e.stopPropagation();
    if (delTimerRef.current) clearTimeout(delTimerRef.current);
    isPressingRef.current = true;
    delTimerRef.current = setTimeout(() => {
        if (isPressingRef.current) {
            handleVirtualInput('CLEAR');
            if (navigator.vibrate) navigator.vibrate(50);
            isPressingRef.current = false; 
        }
    }, 500);
  };

  const handleDelUp = (e: React.PointerEvent) => {
    e.preventDefault(); e.stopPropagation();
    if (delTimerRef.current) { clearTimeout(delTimerRef.current); delTimerRef.current = null; }
    if (isPressingRef.current) { handleVirtualInput('DEL'); isPressingRef.current = false; }
  };

  // --- Range / Slider Logic ---
  const openRangeModal = (varId: string) => {
      setActiveField(null);
      const current = rangeConfigs[varId];
      const currentValue = inputs[varId];
      const validCurrent = currentValue && !isNaN(parseFloat(currentValue)) ? currentValue : '';
      const shouldAutofocus = !validCurrent || validCurrent === '0';

      if (current) {
          const newMax = validCurrent || current.max;
          setTempRange({ min: current.min, max: newMax });
      } else {
          setTempRange({ min: '0', max: validCurrent });
      }

      setActiveRangeModalVar(varId);

      if (shouldAutofocus) {
          setActiveModalInput('max');
          if (!preferNativeKeyboard) setShowKeyboard(true);
      } else {
          setActiveModalInput(null);
          setShowKeyboard(false);
      }
  };

  const handleModalInputFocus = (e: React.FocusEvent<HTMLInputElement>, field: 'min' | 'max') => {
      setActiveModalInput(field);
      setTempRange(prev => ({...prev, [field]: ''}));
      if (!preferNativeKeyboard) setShowKeyboard(true);
      else setShowKeyboard(false);
  };

  const handleSliderSettingsDown = (varId: string) => {
      labelPressTimerRef.current = setTimeout(() => {
          // LONG PRESS ACTION: OPEN CONFIG MODAL (TO EDIT/DELETE)
          if (navigator.vibrate) navigator.vibrate(50);
          openRangeModal(varId);
          labelPressTimerRef.current = null;
      }, 600);
  };

  const handleSliderSettingsUp = (varId: string) => {
      if (labelPressTimerRef.current) {
          // Timer still active = Short Press
          clearTimeout(labelPressTimerRef.current);
          labelPressTimerRef.current = null;

          if (!rangeConfigs[varId]) {
              // No Config -> Open First Time
              openRangeModal(varId);
          } else {
              // Has Config -> Toggle Enabled/Disabled
              setRangeConfigs(prev => ({
                  ...prev,
                  [varId]: { ...prev[varId], enabled: !prev[varId].enabled }
              }));
          }
      }
  };

  const saveRangeConfig = () => {
      if (activeRangeModalVar) {
          const minVal = parseFloat(tempRange.min);
          const maxVal = parseFloat(tempRange.max);

          if (!isNaN(minVal) && !isNaN(maxVal) && minVal < maxVal) {
              const minDec = tempRange.min.includes('.') ? tempRange.min.split('.')[1].length : 0;
              const maxDec = tempRange.max.includes('.') ? tempRange.max.split('.')[1].length : 0;
              const precision = Math.max(minDec, maxDec);
              const step = precision === 0 ? "1" : (1 / Math.pow(10, precision)).toFixed(precision);

              setRangeConfigs(prev => ({
                  ...prev,
                  [activeRangeModalVar]: {
                      min: tempRange.min,
                      max: tempRange.max,
                      enabled: true,
                      step: step,
                      precision: precision
                  }
              }));
          }
          setActiveRangeModalVar(null);
          setActiveModalInput(null);
      }
  };

  const removeSlider = () => {
      if (activeRangeModalVar) {
          setRangeConfigs(prev => {
              const next = { ...prev };
              delete next[activeRangeModalVar];
              return next;
          });
          setActiveRangeModalVar(null);
          setActiveModalInput(null);
      }
  };

  const handleDelete = () => {
      if (isDeleteArmed) {
          onDelete();
      } else {
          setIsDeleteArmed(true);
          setTimeout(() => setIsDeleteArmed(false), 3000);
      }
  };

  const handleForceShowKeyboard = () => {
      setPreferNativeKeyboard(false);
      setShowKeyboard(true);
  };

  const handleHideKeyboardTemp = () => {
      // Just hide the view, do not change preference to native
      setShowKeyboard(false);
  };

  const handleDismissKeyboardPermanently = () => {
      // Hide view AND switch preference to native
      setShowKeyboard(false);
      setPreferNativeKeyboard(true); 
  };

  const copyToClipboard = async (text: string) => {
      try { await navigator.clipboard.writeText(text); } catch (err) { console.error('Failed to copy', err); }
  };

  // Custom styles for specific engineering-style slider and hiding scrollbar
  // Updated to use CSS variable for thumb size
  const customStyles = `
    .no-scrollbar::-webkit-scrollbar {
      display: none;
    }
    .no-scrollbar {
      -ms-overflow-style: none;
      scrollbar-width: none;
    }
    .eng-slider {
      -webkit-appearance: none;
      width: 100%;
      height: var(--thumb-size); /* Track height matches thumb for hit area, visuals handled below */
      background: transparent;
      cursor: pointer;
    }
    .eng-slider:focus {
      outline: none;
    }

    /* Thumb Styling */
    .eng-slider::-webkit-slider-thumb {
      -webkit-appearance: none;
      height: var(--thumb-size); 
      width: 4px; 
      background: #3b82f6; /* Blue-500 */
      cursor: pointer;
      margin-top: 0px; 
      border-radius: 1px;
    }

    /* Track Styling */
    .eng-slider::-webkit-slider-runnable-track {
      width: 100%;
      height: var(--thumb-size);
      cursor: pointer;
      background: rgba(148, 163, 184, 0.2); 
      border-radius: 4px; /* Slightly rounded corners */
    }
  `;

  return (
    <div className={`flex flex-col h-screen bg-${theme}-950 font-sans`}>
      <style>{customStyles}</style>

      {/* Header (Title + Settings + Delete) */}
      <div className={`flex items-center justify-center px-4 bg-${theme}-950 shrink-0 ${uiConfig.headerHeightClass} z-20 sticky top-0 border-b border-${theme}-900 relative`}>
          <div className="absolute left-4 flex gap-2">
            <button 
                onClick={onOpenDevTools} 
                className={`p-2 text-${theme}-600 hover:text-white transition-colors`}
            >
                <Wrench className={uiConfig.iconClassName} />
            </button>
            <button 
                onClick={onOpenSettings} 
                className={`p-2 text-${theme}-600 hover:text-white transition-colors`}
            >
                <Settings className={uiConfig.iconClassName} />
            </button>
          </div>

          <h1 className={`text-white font-bold ${uiConfig.headerClassName} truncate font-mono tracking-widest uppercase`}>{formula.title}</h1>

          <button 
                onClick={handleDelete} 
                className={`absolute right-4 p-2 transition-all rounded-full ${isDeleteArmed ? 'bg-red-900 text-white animate-pulse' : `text-${theme}-600 hover:text-red-400 hover:bg-${theme}-900`}`}
            >
                <Trash2 className={uiConfig.iconClassName} />
            </button>
      </div>

      {/* Fixed LCD Display Result Area */}
      <div 
          onClick={() => handleFieldFocus('target')}
          className={`bg-${theme}-950 ${uiConfig.paddingClass} relative overflow-hidden group/result transition-colors cursor-pointer shrink-0 z-10 border-b border-${theme}-900 shadow-xl ${activeField === 'target' && showKeyboard ? `bg-${theme}-900` : ''}`}
      >
             {/* Result Header */}
             <div className="flex justify-between items-center mb-1 pointer-events-none">
                <span className={`${uiConfig.bodyClassName} font-bold text-blue-500 uppercase tracking-widest truncate max-w-[50%]`}>
                    {formula.resultName || "RESULT"}
                </span>

                {/* Header Actions & Badge */}
                <div className="flex items-center gap-2 pointer-events-auto">
                     <div className={`flex items-center ${uiConfig.bodyClassName} text-${theme}-600 font-bold uppercase`}>
                        {isReverseMode ? (
                            <span className="text-amber-500 animate-pulse flex items-center"><ArrowRightLeft className={`${uiConfig.iconClassName} mr-1`}/> GOAL</span>
                        ) : (
                            "COMPUTE"
                        )}
                    </div>
                    {targetResult && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); setIsReverseMode(false); handleTargetChange(''); }} 
                            className={`p-1 text-${theme}-500 hover:text-red-400`}
                        >
                            <X className={uiConfig.iconClassName}/>
                        </button>
                    )}
                     <button onClick={(e) => { e.stopPropagation(); copyToClipboard(targetResult); }} className={`p-1 text-${theme}-600 hover:text-white`}><Copy className={uiConfig.iconClassName}/></button>
                </div>
             </div>

             {/* Result Value + Unit */}
             <div className="relative flex items-baseline justify-between">
                <div className="flex items-baseline flex-1 min-w-0">
                    <input 
                        type="text"
                        inputMode={preferNativeKeyboard ? "decimal" : "none"}
                        value={targetResult === '0' ? '' : targetResult} 
                        onChange={(e) => handleNativeInputChange('target', e.target.value)}
                        onFocus={() => handleFieldFocus('target')}
                        className={`w-full bg-transparent ${uiConfig.resultFontSize} font-mono text-white outline-none placeholder-slate-800 font-medium tracking-tight pr-12`}
                        placeholder="0"
                    />
                </div>

                 {/* Unit - Anchored to very bottom right, leading-none to remove spacing */}
                 {formula.resultUnit && (
                     <span className={`absolute bottom-0 right-0 ${uiConfig.inputFontSize} leading-none text-${theme}-500 font-mono font-light whitespace-nowrap pointer-events-none`}>{formula.resultUnit}</span>
                 )}
             </div>

             {/* Target Selector (Goal Seek) */}
             {formula.variables.length > 0 && isReverseMode && (
                 <div className="flex items-center justify-end mt-2 pt-2" onClick={(e) => e.stopPropagation()}>
                     <span className={`${uiConfig.bodyClassName} text-${theme}-500 mr-2 uppercase font-bold tracking-widest`}>Solving For:</span>
                     <select 
                        value={solvingVar}
                        onChange={(e) => setSolvingVar(e.target.value)}
                        className={`bg-transparent text-${theme}-300 ${uiConfig.bodyClassName} outline-none font-mono uppercase font-bold`}
                     >
                        {formula.variables.map(v => (
                            <option key={v.symbol} value={v.symbol} className={`bg-${theme}-950 text-white`}>{v.name || v.symbol}</option>
                        ))}
                     </select>
                 </div>
             )}
      </div>

      {/* Main Scrollable Inputs */}
      <div className={`flex-1 overflow-y-auto no-scrollbar transition-all duration-300 ${showKeyboard ? 'pb-80' : 'pb-24'}`}> 

        {/* Info Panel */}
        {showInfo && (
            <div className={`bg-${theme}-950 p-6 animate-fade-in ${uiConfig.bodyClassName} text-${theme}-400 border-b border-${theme}-900`}>
                {formula.description && <p className="mb-4 italic whitespace-pre-wrap leading-relaxed">{formula.description}</p>}
                <p className={`font-mono ${uiConfig.bodyClassName} text-${theme}-600 uppercase tracking-widest`}>JS_EXP: {formula.expression}</p>
            </div>
        )}

        {/* Inputs List - Continuous Field */}
        <div className={`flex flex-col divide-y divide-${theme}-900 border-t border-${theme}-900`}>
             {formula.variables.map(v => {
                 const isSlider = rangeConfigs[v.symbol]?.enabled;
                 const range = rangeConfigs[v.symbol];

                 return (
                 <div 
                    key={v.id} 
                    className={`bg-${theme}-950 transition-colors relative overflow-hidden ${uiConfig.rowHeightClass} shrink-0 ${activeField === v.symbol && !isSlider && showKeyboard ? `bg-${theme}-900` : 'hover:bg-${theme}-900'}`}
                 >
                    {/* Using Flexbox for tight vertical layout with minimal padding */}
                     <div className={`w-full h-full ${uiConfig.paddingClass} flex flex-col justify-between`}>

                        {/* Top Row: Toggle Icon | Name | Unit */}
                        <div className="flex items-center justify-between z-30">
                            <div className="flex items-center gap-2">
                                <button 
                                    className={`text-${theme}-600 hover:text-white p-0 rounded transition-colors ${isSlider ? 'text-blue-500' : ''}`}
                                    onPointerDown={() => handleSliderSettingsDown(v.symbol)}
                                    onPointerUp={() => handleSliderSettingsUp(v.symbol)}
                                    onPointerLeave={() => { if(labelPressTimerRef.current) clearTimeout(labelPressTimerRef.current); }}
                                >
                                    <Sliders className={uiConfig.iconClassName} />
                                </button>
                                <span className={`${uiConfig.bodyClassName} text-${theme}-300 font-bold uppercase tracking-wider leading-tight select-none`}>
                                    {v.name}
                                </span>
                            </div>
                            <span className={`text-${theme}-500 font-medium ${uiConfig.bodyClassName} font-mono whitespace-nowrap overflow-visible pointer-events-none`}>
                                {v.unit || v.symbol}
                            </span>
                        </div>

                        {/* Middle Row: Input Value - Flex Grows */}
                        <div 
                            className="flex-1 flex items-center justify-end z-10 my-1"
                            onClick={() => handleFieldFocus(v.symbol)}
                        >
                             <input 
                                type="text"
                                inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                value={inputs[v.symbol] || ''}
                                onChange={(e) => handleNativeInputChange(v.symbol, e.target.value)}
                                onFocus={() => handleFieldFocus(v.symbol)}
                                className={`w-full bg-transparent text-white font-mono ${uiConfig.inputFontSize} leading-none outline-none placeholder-${theme}-800 text-right font-bold`}
                                placeholder={isSlider ? range.min : "0"}
                            />
                        </div>

                        {/* Bottom Row: Slider Logic or empty spacer */}
                        {isSlider ? (
                            <div className="relative flex items-center" style={{ height: `${uiConfig.iconSize}px` }}>
                                {/* Slider Track - Centered - Removed Left Delete Button */}
                                <div className="absolute left-0 right-8 h-full flex items-center z-20">
                                    <input 
                                        type="range"
                                        min={range.min}
                                        max={range.max}
                                        step={range.step || "1"} 
                                        value={parseFloat(inputs[v.symbol]) || parseFloat(range.min)}
                                        onChange={(e) => handleSliderChange(v.symbol, e.target.value)}
                                        className="eng-slider w-full"
                                    />
                                    {/* Min/Max Labels Inside Slider */}
                                    <div className="absolute top-1/2 -translate-y-1/2 left-2 pointer-events-none text-[8px] font-bold text-${theme}-400 font-mono opacity-80">
                                        {range.min}
                                    </div>
                                    <div className="absolute top-1/2 -translate-y-1/2 right-2 pointer-events-none text-[8px] font-bold text-${theme}-400 font-mono opacity-80">
                                        {range.max}
                                    </div>
                                </div>

                                {/* Reset Value (Right) */}
                                {(inputs[v.symbol] && inputs[v.symbol] !== '0') && (
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); setInputs(prev => ({...prev, [v.symbol]: range.min})); }}
                                        className={`absolute right-0 w-6 h-full flex items-center justify-center text-${theme}-700 hover:text-white transition-colors z-30`}
                                    >
                                        <RotateCcw className={uiConfig.iconClassName} />
                                    </button>
                                )}
                            </div>
                        ) : (
                             // Manual Mode Reset (Bottom Right)
                             <div className="relative" style={{ height: `${Math.max(16, uiConfig.iconSize/2)}px` }}>
                                {(inputs[v.symbol] && inputs[v.symbol] !== '0') && (
                                    <div className="absolute bottom-0 right-0 z-20">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setInputs(prev => ({...prev, [v.symbol]: ''})); }}
                                            className={`text-${theme}-700 hover:text-white transition-colors p-0 flex items-center`}
                                        >
                                            <RotateCcw className={uiConfig.iconClassName} />
                                        </button>
                                    </div>
                                )}
                            </div>
                        )}
                     </div>
                 </div>
                 );
             })}

             <div className="p-8 flex justify-center border-t border-${theme}-900 mt-4">
                 <button 
                    onClick={() => {
                        const initial: Record<string, string> = {};
                        formula.variables.forEach(v => { initial[v.symbol] = ''; });
                        setInputs(initial);
                        setIsReverseMode(false);
                        setTargetResult('');
                        setResult('---');
                        localStorage.removeItem(`calc_inputs_${formula.id}`);
                    }}
                    className={`flex items-center text-${theme}-500 hover:text-white transition-colors ${uiConfig.bodyClassName} font-bold px-8 py-4 uppercase tracking-widest border border-${theme}-900 hover:bg-${theme}-900`}
                 >
                    <RotateCcw className={`${uiConfig.iconClassName} mr-2`} /> Reset Values
                 </button>
             </div>
        </div>
      </div>

      {/* Footer Controls (Flat & Borderless) - No Delete Button */}
      <div className={`bg-${theme}-950 border-t border-${theme}-900 p-0 fixed bottom-0 left-0 right-0 z-30 flex ${uiConfig.headerHeightClass} safe-area-pb`}>
            <button 
                onClick={onBack}
                className={`flex-1 flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}
            >
                <ArrowLeft className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={onEdit} 
                className={`flex-1 flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}
            >
                <Edit2 className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={() => setShowInfo(!showInfo)} 
                className={`flex-1 flex justify-center items-center transition-colors border-r border-${theme}-900 ${showInfo ? `bg-${theme}-900 text-white` : `text-${theme}-500 hover:text-white hover:bg-${theme}-900`}`}
            >
                <Info className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={showKeyboard ? handleDismissKeyboardPermanently : handleForceShowKeyboard}
                className={`flex-1 flex justify-center items-center transition-all active:bg-${theme}-900 ${showKeyboard ? 'bg-blue-600 text-white' : `text-${theme}-500 hover:text-white hover:bg-${theme}-900`}`}
            >
                {showKeyboard ? <ChevronDown className={uiConfig.iconClassName} /> : <Keyboard className={uiConfig.iconClassName} />}
            </button>
      </div>

      {/* Range Config Modal (Flat) */}
      {activeRangeModalVar && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-sm animate-fade-in p-0">
              <div className={`bg-${theme}-950 w-full max-w-xs shadow-2xl border border-${theme}-900`}>
                  <div className={`h-14 flex items-center px-6 border-b border-${theme}-900 ${uiConfig.headerHeightClass}`}>
                    <h3 className={`text-white font-bold ${uiConfig.headerClassName} flex items-center font-mono uppercase tracking-widest`}>
                        <Sliders className={`${uiConfig.iconClassName} mr-3 text-blue-500`}/>
                        Config_Range
                    </h3>
                  </div>
                  <div className="p-6">
                      <div className="flex gap-4 mb-6">
                          <div className="flex-1">
                              <label className={`${uiConfig.bodyClassName} uppercase text-${theme}-500 font-bold mb-2 block tracking-widest`}>Min Value</label>
                              <input 
                                  type="text"
                                  inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                  value={tempRange.min} 
                                  onChange={e => setTempRange(prev => ({...prev, min: e.target.value}))}
                                  onFocus={(e) => handleModalInputFocus(e, 'min')}
                                  className={`w-full bg-${theme}-900/50 p-4 text-white text-lg font-mono outline-none border-b-2 border-transparent focus:border-blue-500 transition-colors`}
                                  placeholder="0"
                              />
                          </div>
                          <div className="flex-1">
                              <label className={`${uiConfig.bodyClassName} uppercase text-${theme}-500 font-bold mb-2 block tracking-widest`}>Max Value</label>
                              <input 
                                  type="text"
                                  inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                  value={tempRange.max} 
                                  onChange={e => setTempRange(prev => ({...prev, max: e.target.value}))}
                                  onFocus={(e) => handleModalInputFocus(e, 'max')}
                                  className={`w-full bg-${theme}-900/50 p-4 text-white text-lg font-mono outline-none border-b-2 border-transparent focus:border-blue-500 transition-colors`}
                                  placeholder="100"
                                  autoFocus={activeModalInput === 'max'}
                              />
                          </div>
                      </div>
                      <div className={`flex border-t border-${theme}-900 -mx-6 -mb-6 ${uiConfig.headerHeightClass}`}>
                          {rangeConfigs[activeRangeModalVar] && (
                               <button onClick={removeSlider} className={`w-14 flex items-center justify-center border-r border-${theme}-900 text-red-500 hover:text-white hover:bg-red-900 transition-colors`}>
                                   <Trash2 className={uiConfig.iconClassName} />
                               </button>
                          )}
                          <button onClick={() => { setActiveRangeModalVar(null); setActiveModalInput(null); setShowKeyboard(false); }} className={`flex-1 bg-${theme}-950 text-${theme}-400 hover:text-white font-bold ${uiConfig.bodyClassName} uppercase tracking-widest hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}>Cancel</button>
                          <button onClick={saveRangeConfig} className={`flex-1 bg-blue-600 text-white hover:bg-blue-500 font-bold ${uiConfig.bodyClassName} uppercase tracking-widest transition-colors`}>Save</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Virtual Keyboard Overlay */}
      <div className={`fixed bottom-0 left-0 right-0 bg-${theme}-950 z-[60] transition-transform duration-200 ease-out pb-safe border-t border-${theme}-900 ${showKeyboard ? 'translate-y-0' : 'translate-y-full'}`}>
          {/* Hide Bar */}
          <div className={`flex justify-center items-center h-10 bg-${theme}-950 border-b border-${theme}-900`}>
              <button onClick={handleHideKeyboardTemp} className={`w-full h-full flex items-center justify-center text-${theme}-500 active:text-white`}>
                  <ChevronDown className={uiConfig.iconClassName} />
              </button>
          </div>

          {/* Grid */}
          <div className="grid grid-cols-4 gap-px bg-${theme}-900">
              {[1, 2, 3].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
               <button onPointerDown={handleDelDown} onPointerUp={handleDelUp} onPointerLeave={handleDelUp} onClick={(e) => e.preventDefault()} className={`h-[55px] bg-${theme}-950 text-xl font-medium text-red-500 active:bg-${theme}-900 flex items-center justify-center touch-none hover:bg-${theme}-900 transition-colors`}><Delete className="w-6 h-6" /></button>

              {[4, 5, 6].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
              <button onClick={() => handleVirtualInput('-')} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 flex items-center justify-center hover:bg-${theme}-900 transition-colors`}><Minus className="w-6 h-6" /></button>

              {[7, 8, 9].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
              <button onClick={() => handleVirtualInput('.')} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>.</button>

              <div className="col-span-2">
                  <button onClick={() => handleVirtualInput('0')} className={`h-[55px] w-full bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>0</button>
              </div>
              <div className="col-span-2">
                   <button onClick={() => handleVirtualInput('DONE')} className={`h-[55px] w-full bg-blue-600 text-white font-bold ${uiConfig.bodyClassName} uppercase tracking-widest active:bg-blue-500 flex items-center justify-center transition-colors`}>DONE</button>
              </div>
          </div>
      </div>
    </div>
  );
};

export interface Variable {
  id: string;
  name: string; // The display name, e.g., "Distance"
  symbol: string; // The variable used in math, e.g., "d"
  unit?: string; // e.g. "km", "kg"
  defaultValue?: number;
}

export interface FormulaOutput {
  id: string;
  name: string; // e.g. "Area"
  unit: string; // e.g. "m2"
  expression: string; // e.g. "w * h"
}

export interface Formula {
  id: string;
  title: string;
  description: string;
  variables: Variable[];
  outputs: FormulaOutput[]; // Changed from single expression to array
  color: string; // For UI aesthetics
  icon: string; // Icon name
  originalPrompt?: string; // The AI prompt used to generate this formula
  aiJson?: string; // The raw JSON response from AI

  // Deprecated fields kept for type safety during migration if needed, though we will migrate immediately
  expression?: string; 
  resultUnit?: string;
  resultName?: string;
}

export type ViewState = 'DASHBOARD' | 'EDITOR' | 'RUNNER';

export interface AIFormulaResponse {
  title: string;
  variables: { name: string; symbol: string; unit?: string }[];
  outputs: { name: string; unit: string; expression: string }[]; // Updated schema
  explanation?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIFormulaResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const SYSTEM_PROMPT_TEMPLATE = `
You are a backend API that generates configuration for a calculator application.
Your task is to convert the user's natural language description into a strict JSON object.

**STRICT OUTPUT RULES:**
1.  **OUTPUT FORMAT:** Return the JSON object enclosed in a markdown code block (e.g., \`\`\`json ... \`\`\`).
2.  **FORMATTING:** The JSON **MUST** be pretty-printed with indentation (2 spaces) and newlines. Do not minify.
3.  **LANGUAGE:** All visible text (title, names, units, explanation) MUST be in **RUSSIAN**.
4.  **VARIABLES:**
    *   Keep symbols simple (a, b, x, y, w, h).
    *   Variable names should be human-readable (e.g., "Ширина", "Вес").
    *   Infer standard units if possible (kg, m, cm, rub).
5.  **OUTPUTS (RESULTS):**
    *   The user request might require **MULTIPLE** results (e.g., if asked for "Rectangle", return "Area" AND "Perimeter").
    *   Provide an array of 'outputs'. Each has a name, unit, and JS expression.
6.  **EXPRESSION:** Must be valid, executable JavaScript math (e.g., "a * b", "Math.PI * Math.pow(r, 2)").
7.  **EXPLANATION:** A short, helpful guide (2 sentences) on how to use this tool.

**JSON SCHEMA:**
{
  "title": "String (Max 4 words)",
  "variables": [
    {
      "name": "String (Display Name)",
      "symbol": "String (JS variable name)",
      "unit": "String (Optional unit)"
    }
  ],
  "outputs": [
    {
      "name": "String (Label for answer, e.g. 'Площадь')",
      "unit": "String (Unit for answer, e.g. 'm2')",
      "expression": "String (JS Formula, e.g. 'w * h')"
    }
  ],
  "explanation": "String (User guide)"
}
`;

// Robust parser that handles Markdown code blocks and common JSON errors from LLMs
export const cleanAndParseJSON = (text: string): AIFormulaResponse => {
    let cleanText = text.trim();

    // Remove Markdown code blocks if present (```json ... ```)
    cleanText = cleanText.replace(/^```json\s*/i, "").replace(/^```\s*/i, "");
    cleanText = cleanText.replace(/\s*```$/, "");

    // Attempt to find the first { and last } to strip conversational garbage
    const firstBrace = cleanText.indexOf('{');
    const lastBrace = cleanText.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1) {
        cleanText = cleanText.substring(firstBrace, lastBrace + 1);
    }

    try {
        const parsed = JSON.parse(cleanText);

        // Migration/Sanitization for AI being stubborn with old format
        if (!parsed.outputs && parsed.expression) {
            parsed.outputs = [{
                name: parsed.resultName || "Result",
                unit: parsed.resultUnit || "",
                expression: parsed.expression
            }];
        }

        return parsed as AIFormulaResponse;
    } catch (e) {
        console.error("JSON Parse Error:", e);
        throw new Error("Failed to parse JSON. Please ensure the AI output is valid.");
    }
};

export const generateFormulaFromDescription = async (description: string): Promise<{ data: AIFormulaResponse, raw: string }> => {
  const model = "gemini-2.5-flash";

  const prompt = `${SYSTEM_PROMPT_TEMPLATE}

  USER REQUEST: "${description}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "text/plain", // We want raw text with code blocks now
      }
    });

    if (response.text) {
      const parsedData = cleanAndParseJSON(response.text);
      return { data: parsedData, raw: response.text };
    }
    throw new Error("No response from AI");
  } catch (error) {
    console.error("Error generating formula:", error);
    throw error;
  }
};

