import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, ArrowRightLeft, Info, RotateCcw, Edit2, Copy, Trash2, Keyboard, ChevronDown, Delete, X, Minus, Sliders, Settings, Wrench } from 'lucide-react';
import { Formula } from '../types';

interface FormulaRunnerProps {
  formula: Formula;
  onBack: () => void;
  onEdit: () => void;
  onDelete: () => void;
  theme: string;
  uiConfig: any;
  onOpenSettings: () => void;
  onOpenDevTools: () => void;
}

interface RangeConfig {
  min: string;
  max: string;
  enabled: boolean;
  step?: string;
  precision?: number;
}

export const FormulaRunner: React.FC<FormulaRunnerProps> = ({ formula, onBack, onEdit, onDelete, theme, uiConfig, onOpenSettings, onOpenDevTools }) => {
  // Inputs & Calculation State
  const [inputs, setInputs] = useState<Record<string, string>>({});

  // Results State: Map output ID to string value
  const [results, setResults] = useState<Record<string, string>>({});

  // Target State for Goal Seek: which output ID is being edited?
  const [targetOutputId, setTargetOutputId] = useState<string | null>(null);

  // UI State
  const [showInfo, setShowInfo] = useState(false);
  const [isDeleteArmed, setIsDeleteArmed] = useState(false);
  const [showKeyboard, setShowKeyboard] = useState(false);
  const [preferNativeKeyboard, setPreferNativeKeyboard] = useState(false);

  // Tracks which field is active: variable symbol OR output ID (prefixed with 'out_')
  const [activeField, setActiveField] = useState<string | null>(null);

  // Slider / Range State
  const [rangeConfigs, setRangeConfigs] = useState<Record<string, RangeConfig>>({});
  const [activeRangeModalVar, setActiveRangeModalVar] = useState<string | null>(null);
  const [tempRange, setTempRange] = useState({ min: '', max: '' });
  const [activeModalInput, setActiveModalInput] = useState<'min' | 'max' | null>(null);

  // Long press logic refs
  const delTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isPressingRef = useRef(false);
  const labelPressTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Goal Seek State
  const [solvingVar, setSolvingVar] = useState<string>(formula.variables[0]?.symbol || '');

  const isReverseMode = targetOutputId !== null;

  // Load state from localStorage on mount
  useEffect(() => {
    // Load Inputs
    const savedInputs = localStorage.getItem(`calc_inputs_${formula.id}`);
    const initialInputs: Record<string, string> = {};

    if (savedInputs) {
        try {
            const parsed = JSON.parse(savedInputs);
            setInputs(parsed);
        } catch (e) {
            formula.variables.forEach(v => {
               initialInputs[v.symbol] = v.defaultValue !== undefined ? String(v.defaultValue) : '';
            });
            setInputs(initialInputs);
        }
    } else {
        formula.variables.forEach(v => {
           initialInputs[v.symbol] = v.defaultValue !== undefined ? String(v.defaultValue) : '';
        });
        setInputs(initialInputs);
    }

    // Load Range Configs
    const savedRanges = localStorage.getItem(`calc_ranges_${formula.id}`);
    if (savedRanges) {
        try {
            setRangeConfigs(JSON.parse(savedRanges));
        } catch (e) {
            console.error("Failed to parse saved ranges");
        }
    }
  }, [formula.id]);

  // Save inputs and ranges to localStorage
  useEffect(() => {
     if (Object.keys(inputs).length > 0) {
        localStorage.setItem(`calc_inputs_${formula.id}`, JSON.stringify(inputs));
     }
  }, [inputs, formula.id]);

  useEffect(() => {
      localStorage.setItem(`calc_ranges_${formula.id}`, JSON.stringify(rangeConfigs));
  }, [rangeConfigs, formula.id]);

  // Helper to get numeric inputs
  const getNumericInputs = (currentInputs: Record<string, string>) => {
      const calcInputs: Record<string, number> = {};
      Object.keys(currentInputs).forEach(k => {
          const valStr = currentInputs[k].replace(',', '.');
          const val = valStr === '' || valStr === '-' ? 0 : parseFloat(valStr);
          calcInputs[k] = isNaN(val) ? 0 : val;
      });
      return calcInputs;
  };

  // Evaluate a specific expression with given inputs
  const evaluateExpression = (expression: string, numInputs: Record<string, number>) => {
      try {
          const names = Object.keys(numInputs);
          const values = Object.values(numInputs);
          const func = new Function(...names, `return (${expression});`);
          const res = func(...values);
          return isNaN(res) || !isFinite(res) ? 'Error' : res;
      } catch {
          return 'Error';
      }
  };

  // Main Calculation Effect (Forward)
  useEffect(() => {
    if (!isReverseMode) {
        const numInputs = getNumericInputs(inputs);
        const newResults: Record<string, string> = {};

        formula.outputs.forEach(output => {
            const res = evaluateExpression(output.expression, numInputs);
            if (typeof res === 'number') {
                newResults[output.id] = String(Math.round(res * 10000) / 10000);
            } else {
                newResults[output.id] = String(res);
            }
        });
        setResults(newResults);
    }
  }, [inputs, formula.outputs, isReverseMode]);

  // Goal Seek Logic
  const solveForTarget = (targetVal: number, varSymbol: string, expression: string) => {
    let currentInputsNumeric = getNumericInputs(inputs);

    let x0 = currentInputsNumeric[varSymbol] || 1; 
    let x1 = x0 + 0.1;
    const maxIter = 50;
    const tolerance = 0.0001;

    const calc = (val: number) => {
        const temp = { ...currentInputsNumeric, [varSymbol]: val };
        const valRes = evaluateExpression(expression, temp);
        return typeof valRes === 'number' ? valRes : 0;
    };

    for (let i = 0; i < maxIter; i++) {
        const y0 = calc(x0);
        const y1 = calc(x1);

        if (Math.abs(y1 - targetVal) < tolerance) {
            setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
            return;
        }
        if (Math.abs(y1 - y0) < 1e-9) {
            x1 = x1 + Math.random(); 
            continue;
        }
        const x_new = x1 - (y1 - targetVal) * (x1 - x0) / (y1 - y0);
        x0 = x1;
        x1 = x_new;
    }
    setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
  };

  const handleTargetChange = (outputId: string, val: string) => {
    setTargetOutputId(outputId);

    // Update local results display instantly for UX
    setResults(prev => ({...prev, [outputId]: val}));

    const num = parseFloat(val.replace(',', '.'));
    const targetOutput = formula.outputs.find(o => o.id === outputId);

    if (targetOutput && !isNaN(num) && solvingVar && val.trim() !== '' && val !== '-') {
        solveForTarget(num, solvingVar, targetOutput.expression);

        // After solving, calculate OTHER outputs based on the new input
        // We delay slightly or let the next render cycle handle the input update -> forward calc
    }
  };

  const handleNativeInputChange = (id: string, val: string) => {
      let processedVal = val;

      if (id.startsWith('out_')) {
          // It's a Result Field
          const actualOutputId = id.replace('out_', '');
          handleTargetChange(actualOutputId, processedVal);
      } else {
          // It's a Variable Field
          setInputs(prev => ({...prev, [id]: processedVal}));
          setTargetOutputId(null); // Exit reverse mode

          // Auto-update slider MAX if enabled and value is not 0
          if (rangeConfigs[id]?.enabled) {
              const numVal = parseFloat(processedVal);
              if (!isNaN(numVal) && numVal !== 0 && processedVal !== '') {
                  setRangeConfigs(prev => ({
                      ...prev,
                      [id]: {
                          ...prev[id],
                          max: processedVal
                      }
                  }));
              }
          }
      }
  };

  const handleSliderChange = (id: string, val: string) => {
      setInputs(prev => ({...prev, [id]: val}));
      setTargetOutputId(null);
  };

  const handleFieldFocus = (fieldId: string) => {
      setActiveField(fieldId);

      if (fieldId.startsWith('out_')) {
          setTargetOutputId(fieldId.replace('out_', ''));
      } else {
          // It is a variable input

          // Do not show keyboard if slider is enabled for this field
          if (rangeConfigs[fieldId]?.enabled) {
              setShowKeyboard(false);
              return;
          }
      }

      if (!preferNativeKeyboard) {
          setShowKeyboard(true);
      } else {
          setShowKeyboard(false);
      }
  };

  // --- Keyboard Logic (Virtual) ---
  const handleVirtualInput = (char: string) => {
      const processInput = (prev: string) => {
          if (char === 'CLEAR') return '';
          if (char === 'DEL') return prev.slice(0, -1);
          if (char === 'DONE') {
              handleDismissKeyboardPermanently();
              return prev;
          }
          if (char === '-') {
             if (prev.startsWith('-')) return prev.slice(1);
             return '-' + prev;
          }
          let newChar = char;
          if (newChar === ',') newChar = '.';
          if (newChar === '.') {
              if (prev.includes('.') || prev.includes(',')) return prev;
              if (prev === '') return '0.';
              return prev + '.';
          }
          if (prev === '0' && !isNaN(parseInt(newChar))) return '0.' + newChar;
          return prev + newChar;
      };

      // Modal Virtual Input Logic
      if (activeRangeModalVar && activeModalInput) {
          setTempRange(prev => ({
              ...prev,
              [activeModalInput]: processInput(prev[activeModalInput])
          }));
          return;
      }

      // Main Logic
      if (!activeField) return;

      if (activeField.startsWith('out_')) {
          const outId = activeField.replace('out_', '');
          const currentVal = results[outId] || '';
          handleTargetChange(outId, processInput(currentVal));
      } else {
          setInputs(prev => ({ ...prev, [activeField]: processInput(prev[activeField] || '') }));
          setTargetOutputId(null);

          // Slider Logic for Virtual Input
          if (rangeConfigs[activeField]?.enabled) {
             const newVal = processInput(inputs[activeField] || '');
             const numVal = parseFloat(newVal);
             if (!isNaN(numVal) && numVal !== 0 && newVal !== '') {
                 setRangeConfigs(prev => ({
                    ...prev,
                    [activeField]: { ...prev[activeField], max: newVal }
                 }));
             }
          }
      }
  };

  const handleDelDown = (e: React.PointerEvent) => {
    e.preventDefault(); e.stopPropagation();
    if (delTimerRef.current) clearTimeout(delTimerRef.current);
    isPressingRef.current = true;
    delTimerRef.current = setTimeout(() => {
        if (isPressingRef.current) {
            handleVirtualInput('CLEAR');
            if (navigator.vibrate) navigator.vibrate(50);
            isPressingRef.current = false; 
        }
    }, 500);
  };

  const handleDelUp = (e: React.PointerEvent) => {
    e.preventDefault(); e.stopPropagation();
    if (delTimerRef.current) { clearTimeout(delTimerRef.current); delTimerRef.current = null; }
    if (isPressingRef.current) { handleVirtualInput('DEL'); isPressingRef.current = false; }
  };

  // --- Range / Slider Logic ---
  const openRangeModal = (varId: string) => {
      setActiveField(null);
      const current = rangeConfigs[varId];
      const currentValue = inputs[varId];
      const validCurrent = currentValue && !isNaN(parseFloat(currentValue)) ? currentValue : '';
      const shouldAutofocus = !validCurrent || validCurrent === '0';

      if (current) {
          const newMax = validCurrent || current.max;
          setTempRange({ min: current.min, max: newMax });
      } else {
          setTempRange({ min: '0', max: validCurrent });
      }

      setActiveRangeModalVar(varId);

      if (shouldAutofocus) {
          setActiveModalInput('max');
          if (!preferNativeKeyboard) setShowKeyboard(true);
      } else {
          setActiveModalInput(null);
          setShowKeyboard(false);
      }
  };

  const handleModalInputFocus = (e: React.FocusEvent<HTMLInputElement>, field: 'min' | 'max') => {
      setActiveModalInput(field);
      setTempRange(prev => ({...prev, [field]: ''}));
      if (!preferNativeKeyboard) setShowKeyboard(true);
      else setShowKeyboard(false);
  };

  const handleSliderSettingsDown = (varId: string) => {
      labelPressTimerRef.current = setTimeout(() => {
          // LONG PRESS ACTION: OPEN CONFIG MODAL (TO EDIT/DELETE)
          if (navigator.vibrate) navigator.vibrate(50);
          openRangeModal(varId);
          labelPressTimerRef.current = null;
      }, 600);
  };

  const handleSliderSettingsUp = (varId: string) => {
      if (labelPressTimerRef.current) {
          // Timer still active = Short Press
          clearTimeout(labelPressTimerRef.current);
          labelPressTimerRef.current = null;

          if (!rangeConfigs[varId]) {
              // No Config -> Open First Time
              openRangeModal(varId);
          } else {
              // Has Config -> Toggle Enabled/Disabled
              setRangeConfigs(prev => ({
                  ...prev,
                  [varId]: { ...prev[varId], enabled: !prev[varId].enabled }
              }));
          }
      }
  };

  const saveRangeConfig = () => {
      if (activeRangeModalVar) {
          const minVal = parseFloat(tempRange.min);
          const maxVal = parseFloat(tempRange.max);

          if (!isNaN(minVal) && !isNaN(maxVal) && minVal < maxVal) {
              const minDec = tempRange.min.includes('.') ? tempRange.min.split('.')[1].length : 0;
              const maxDec = tempRange.max.includes('.') ? tempRange.max.split('.')[1].length : 0;
              const precision = Math.max(minDec, maxDec);
              const step = precision === 0 ? "1" : (1 / Math.pow(10, precision)).toFixed(precision);

              setRangeConfigs(prev => ({
                  ...prev,
                  [activeRangeModalVar]: {
                      min: tempRange.min,
                      max: tempRange.max,
                      enabled: true,
                      step: step,
                      precision: precision
                  }
              }));
          }
          setActiveRangeModalVar(null);
          setActiveModalInput(null);
      }
  };

  const removeSlider = () => {
      if (activeRangeModalVar) {
          setRangeConfigs(prev => {
              const next = { ...prev };
              delete next[activeRangeModalVar];
              return next;
          });
          setActiveRangeModalVar(null);
          setActiveModalInput(null);
      }
  };

  const handleDelete = () => {
      if (isDeleteArmed) {
          onDelete();
      } else {
          setIsDeleteArmed(true);
          setTimeout(() => setIsDeleteArmed(false), 3000);
      }
  };

  const handleForceShowKeyboard = () => {
      setPreferNativeKeyboard(false);
      setShowKeyboard(true);
  };

  const handleHideKeyboardTemp = () => {
      // Just hide the view, do not change preference to native
      setShowKeyboard(false);
  };

  const handleDismissKeyboardPermanently = () => {
      // Hide view AND switch preference to native
      setShowKeyboard(false);
      setPreferNativeKeyboard(true); 
  };

  const copyToClipboard = async (text: string) => {
      try { await navigator.clipboard.writeText(text); } catch (err) { console.error('Failed to copy', err); }
  };

  // Custom styles for specific engineering-style slider and hiding scrollbar
  // Updated to use CSS variable for thumb size
  const customStyles = `
    .no-scrollbar::-webkit-scrollbar {
      display: none;
    }
    .no-scrollbar {
      -ms-overflow-style: none;
      scrollbar-width: none;
    }
    .eng-slider {
      -webkit-appearance: none;
      width: 100%;
      height: var(--thumb-size); /* Track height matches thumb for hit area, visuals handled below */
      background: transparent;
      cursor: pointer;
    }
    .eng-slider:focus {
      outline: none;
    }

    /* Thumb Styling */
    .eng-slider::-webkit-slider-thumb {
      -webkit-appearance: none;
      height: var(--thumb-size); 
      width: 4px; 
      background: #3b82f6; /* Blue-500 */
      cursor: pointer;
      margin-top: 0px; 
      border-radius: 1px;
    }

    /* Track Styling */
    .eng-slider::-webkit-slider-runnable-track {
      width: 100%;
      height: var(--thumb-size);
      cursor: pointer;
      background: rgba(148, 163, 184, 0.2); 
      border-radius: 4px; /* Slightly rounded corners */
    }
  `;

  return (
    <div className={`flex flex-col h-screen bg-${theme}-950 font-sans`}>
      <style>{customStyles}</style>

      {/* Header (Title + Settings + Delete) */}
      <div className={`flex items-center justify-center px-4 bg-${theme}-950 shrink-0 ${uiConfig.headerHeightClass} z-20 sticky top-0 border-b border-${theme}-900 relative`}>
          <div className="absolute left-4 flex gap-2">
            <button 
                onClick={onOpenDevTools} 
                className={`p-2 text-${theme}-600 hover:text-white transition-colors`}
            >
                <Wrench className={uiConfig.iconClassName} />
            </button>
            <button 
                onClick={onOpenSettings} 
                className={`p-2 text-${theme}-600 hover:text-white transition-colors`}
            >
                <Settings className={uiConfig.iconClassName} />
            </button>
          </div>

          <h1 className={`text-white font-bold ${uiConfig.headerClassName} truncate font-mono tracking-widest uppercase`}>{formula.title}</h1>

          <button 
                onClick={handleDelete} 
                className={`absolute right-4 p-2 transition-all rounded-full ${isDeleteArmed ? 'bg-red-900 text-white animate-pulse' : `text-${theme}-600 hover:text-red-400 hover:bg-${theme}-900`}`}
            >
                <Trash2 className={uiConfig.iconClassName} />
            </button>
      </div>

      {/* Fixed LCD Display Result Areas - Stacked if multiple */}
      <div className="flex flex-col shrink-0 z-10 shadow-xl">
          {formula.outputs.map((output, idx) => {
              const val = results[output.id] || '---';
              const isActive = activeField === `out_${output.id}`;
              const isTarget = targetOutputId === output.id;

              return (
              <div 
                  key={output.id}
                  onClick={() => handleFieldFocus(`out_${output.id}`)}
                  className={`bg-${theme}-950 ${uiConfig.paddingClass} relative overflow-hidden group/result transition-colors cursor-pointer border-b border-${theme}-900 ${isActive && showKeyboard ? `bg-${theme}-900` : ''}`}
              >
                     {/* Result Header */}
                     <div className="flex justify-between items-center mb-1 pointer-events-none">
                        <span className={`${uiConfig.bodyClassName} font-bold text-blue-500 uppercase tracking-widest truncate max-w-[50%]`}>
                            {output.name || `RESULT ${idx + 1}`}
                        </span>

                        {/* Header Actions & Badge */}
                        <div className="flex items-center gap-2 pointer-events-auto">
                             <div className={`flex items-center ${uiConfig.bodyClassName} text-${theme}-600 font-bold uppercase`}>
                                {isTarget ? (
                                    <span className="text-amber-500 animate-pulse flex items-center"><ArrowRightLeft className={`${uiConfig.iconClassName} mr-1`}/> GOAL</span>
                                ) : (
                                    "COMPUTE"
                                )}
                            </div>
                            {(isTarget && val) && (
                                <button 
                                    onClick={(e) => { e.stopPropagation(); setTargetOutputId(null); handleTargetChange(output.id, ''); }} 
                                    className={`p-1 text-${theme}-500 hover:text-red-400`}
                                >
                                    <X className={uiConfig.iconClassName}/>
                                </button>
                            )}
                             <button onClick={(e) => { e.stopPropagation(); copyToClipboard(val); }} className={`p-1 text-${theme}-600 hover:text-white`}><Copy className={uiConfig.iconClassName}/></button>
                        </div>
                     </div>

                     {/* Result Value + Unit */}
                     <div className="relative flex items-baseline justify-between">
                        <div className="flex items-baseline flex-1 min-w-0">
                            <input 
                                type="text"
                                inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                value={val === '0' ? '' : val} 
                                onChange={(e) => handleNativeInputChange(`out_${output.id}`, e.target.value)}
                                onFocus={() => handleFieldFocus(`out_${output.id}`)}
                                className={`w-full bg-transparent ${uiConfig.resultFontSize} font-mono text-white outline-none placeholder-slate-800 font-medium tracking-tight pr-12`}
                                placeholder="0"
                            />
                        </div>

                         {/* Unit */}
                         {output.unit && (
                             <span className={`absolute bottom-0 right-0 ${uiConfig.inputFontSize} leading-none text-${theme}-500 font-mono font-light whitespace-nowrap pointer-events-none`}>{output.unit}</span>
                         )}
                     </div>
              </div>
              );
          })}

          {/* Target Selector (Goal Seek) - Only shows when one is active */}
          {formula.variables.length > 0 && targetOutputId && (
                 <div className={`flex items-center justify-end px-4 py-2 bg-${theme}-950 border-b border-${theme}-900`} onClick={(e) => e.stopPropagation()}>
                     <span className={`${uiConfig.bodyClassName} text-${theme}-500 mr-2 uppercase font-bold tracking-widest`}>Solving For:</span>
                     <select 
                        value={solvingVar}
                        onChange={(e) => setSolvingVar(e.target.value)}
                        className={`bg-transparent text-${theme}-300 ${uiConfig.bodyClassName} outline-none font-mono uppercase font-bold`}
                     >
                        {formula.variables.map(v => (
                            <option key={v.symbol} value={v.symbol} className={`bg-${theme}-950 text-white`}>{v.name || v.symbol}</option>
                        ))}
                     </select>
                 </div>
          )}
      </div>

      {/* Main Scrollable Inputs */}
      <div className={`flex-1 overflow-y-auto no-scrollbar transition-all duration-300 ${showKeyboard ? 'pb-80' : 'pb-24'}`}> 

        {/* Info Panel */}
        {showInfo && (
            <div className={`bg-${theme}-950 p-6 animate-fade-in ${uiConfig.bodyClassName} text-${theme}-400 border-b border-${theme}-900`}>
                {formula.description && <p className="mb-4 italic whitespace-pre-wrap leading-relaxed">{formula.description}</p>}
                <div className="space-y-2">
                    {formula.outputs.map((o, i) => (
                        <p key={i} className={`font-mono ${uiConfig.bodyClassName} text-${theme}-600 uppercase tracking-widest`}>
                            {o.name}: {o.expression}
                        </p>
                    ))}
                </div>
            </div>
        )}

        {/* Inputs List - Continuous Field */}
        <div className={`flex flex-col divide-y divide-${theme}-900 border-t border-${theme}-900`}>
             {formula.variables.map(v => {
                 const isSlider = rangeConfigs[v.symbol]?.enabled;
                 const range = rangeConfigs[v.symbol];

                 return (
                 <div 
                    key={v.id} 
                    className={`bg-${theme}-950 transition-colors relative overflow-hidden ${uiConfig.rowHeightClass} shrink-0 ${activeField === v.symbol && !isSlider && showKeyboard ? `bg-${theme}-900` : 'hover:bg-${theme}-900'}`}
                 >
                    {/* Using Flexbox for tight vertical layout with minimal padding */}
                     <div className={`w-full h-full ${uiConfig.paddingClass} flex flex-col justify-between`}>

                        {/* Top Row: Toggle Icon | Name | Unit */}
                        <div className="flex items-center justify-between z-30">
                            <div className="flex items-center gap-2">
                                <button 
                                    className={`text-${theme}-600 hover:text-white p-0 rounded transition-colors ${isSlider ? 'text-blue-500' : ''}`}
                                    onPointerDown={() => handleSliderSettingsDown(v.symbol)}
                                    onPointerUp={() => handleSliderSettingsUp(v.symbol)}
                                    onPointerLeave={() => { if(labelPressTimerRef.current) clearTimeout(labelPressTimerRef.current); }}
                                >
                                    <Sliders className={uiConfig.iconClassName} />
                                </button>
                                <span className={`${uiConfig.bodyClassName} text-${theme}-300 font-bold uppercase tracking-wider leading-tight select-none`}>
                                    {v.name}
                                </span>
                            </div>
                            <span className={`text-${theme}-500 font-medium ${uiConfig.bodyClassName} font-mono whitespace-nowrap overflow-visible pointer-events-none`}>
                                {v.unit || v.symbol}
                            </span>
                        </div>

                        {/* Middle Row: Input Value - Flex Grows */}
                        <div 
                            className="flex-1 flex items-center justify-end z-10 my-1"
                            onClick={() => handleFieldFocus(v.symbol)}
                        >
                             <input 
                                type="text"
                                inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                value={inputs[v.symbol] || ''}
                                onChange={(e) => handleNativeInputChange(v.symbol, e.target.value)}
                                onFocus={() => handleFieldFocus(v.symbol)}
                                className={`w-full bg-transparent text-white font-mono ${uiConfig.inputFontSize} leading-none outline-none placeholder-${theme}-800 text-right font-bold`}
                                placeholder={isSlider ? range.min : "0"}
                            />
                        </div>

                        {/* Bottom Row: Slider Logic or empty spacer */}
                        {isSlider ? (
                            <div className="relative flex items-center" style={{ height: `${uiConfig.iconSize}px` }}>
                                {/* Slider Track - Centered - Removed Left Delete Button */}
                                <div className="absolute left-0 right-8 h-full flex items-center z-20">
                                    <input 
                                        type="range"
                                        min={range.min}
                                        max={range.max}
                                        step={range.step || "1"} 
                                        value={parseFloat(inputs[v.symbol]) || parseFloat(range.min)}
                                        onChange={(e) => handleSliderChange(v.symbol, e.target.value)}
                                        className="eng-slider w-full"
                                    />
                                    {/* Min/Max Labels Inside Slider */}
                                    <div className="absolute top-1/2 -translate-y-1/2 left-2 pointer-events-none text-[8px] font-bold text-${theme}-400 font-mono opacity-80">
                                        {range.min}
                                    </div>
                                    <div className="absolute top-1/2 -translate-y-1/2 right-2 pointer-events-none text-[8px] font-bold text-${theme}-400 font-mono opacity-80">
                                        {range.max}
                                    </div>
                                </div>

                                {/* Reset Value (Right) */}
                                {(inputs[v.symbol] && inputs[v.symbol] !== '0') && (
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); setInputs(prev => ({...prev, [v.symbol]: range.min})); }}
                                        className={`absolute right-0 w-6 h-full flex items-center justify-center text-${theme}-700 hover:text-white transition-colors z-30`}
                                    >
                                        <RotateCcw className={uiConfig.iconClassName} />
                                    </button>
                                )}
                            </div>
                        ) : (
                             // Manual Mode Reset (Bottom Right)
                             <div className="relative" style={{ height: `${Math.max(16, uiConfig.iconSize/2)}px` }}>
                                {(inputs[v.symbol] && inputs[v.symbol] !== '0') && (
                                    <div className="absolute bottom-0 right-0 z-20">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setInputs(prev => ({...prev, [v.symbol]: ''})); }}
                                            className={`text-${theme}-700 hover:text-white transition-colors p-0 flex items-center`}
                                        >
                                            <RotateCcw className={uiConfig.iconClassName} />
                                        </button>
                                    </div>
                                )}
                            </div>
                        )}
                     </div>
                 </div>
                 );
             })}

             <div className="p-8 flex justify-center border-t border-${theme}-900 mt-4">
                 <button 
                    onClick={() => {
                        const initial: Record<string, string> = {};
                        formula.variables.forEach(v => { initial[v.symbol] = ''; });
                        setInputs(initial);
                        setTargetOutputId(null);
                        setResults({});
                        localStorage.removeItem(`calc_inputs_${formula.id}`);
                    }}
                    className={`flex items-center text-${theme}-500 hover:text-white transition-colors ${uiConfig.bodyClassName} font-bold px-8 py-4 uppercase tracking-widest border border-${theme}-900 hover:bg-${theme}-900`}
                 >
                    <RotateCcw className={`${uiConfig.iconClassName} mr-2`} /> Reset Values
                 </button>
             </div>
        </div>
      </div>

      {/* Footer Controls (Flat & Borderless) - No Delete Button */}
      <div className={`bg-${theme}-950 border-t border-${theme}-900 p-0 fixed bottom-0 left-0 right-0 z-30 flex ${uiConfig.headerHeightClass} safe-area-pb`}>
            <button 
                onClick={onBack}
                className={`flex-1 flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}
            >
                <ArrowLeft className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={onEdit} 
                className={`flex-1 flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}
            >
                <Edit2 className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={() => setShowInfo(!showInfo)} 
                className={`flex-1 flex justify-center items-center transition-colors border-r border-${theme}-900 ${showInfo ? `bg-${theme}-900 text-white` : `text-${theme}-500 hover:text-white hover:bg-${theme}-900`}`}
            >
                <Info className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={showKeyboard ? handleDismissKeyboardPermanently : handleForceShowKeyboard}
                className={`flex-1 flex justify-center items-center transition-all active:bg-${theme}-900 ${showKeyboard ? 'bg-blue-600 text-white' : `text-${theme}-500 hover:text-white hover:bg-${theme}-900`}`}
            >
                {showKeyboard ? <ChevronDown className={uiConfig.iconClassName} /> : <Keyboard className={uiConfig.iconClassName} />}
            </button>
      </div>

      {/* Range Config Modal (Flat) */}
      {activeRangeModalVar && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-sm animate-fade-in p-0">
              <div className={`bg-${theme}-950 w-full max-w-xs shadow-2xl border border-${theme}-900`}>
                  <div className={`h-14 flex items-center px-6 border-b border-${theme}-900 ${uiConfig.headerHeightClass}`}>
                    <h3 className={`text-white font-bold ${uiConfig.headerClassName} flex items-center font-mono uppercase tracking-widest`}>
                        <Sliders className={`${uiConfig.iconClassName} mr-3 text-blue-500`}/>
                        Config_Range
                    </h3>
                  </div>
                  <div className="p-6">
                      <div className="flex gap-4 mb-6">
                          <div className="flex-1">
                              <label className={`${uiConfig.bodyClassName} uppercase text-${theme}-500 font-bold mb-2 block tracking-widest`}>Min Value</label>
                              <input 
                                  type="text"
                                  inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                  value={tempRange.min} 
                                  onChange={e => setTempRange(prev => ({...prev, min: e.target.value}))}
                                  onFocus={(e) => handleModalInputFocus(e, 'min')}
                                  className={`w-full bg-${theme}-900/50 p-4 text-white text-lg font-mono outline-none border-b-2 border-transparent focus:border-blue-500 transition-colors`}
                                  placeholder="0"
                              />
                          </div>
                          <div className="flex-1">
                              <label className={`${uiConfig.bodyClassName} uppercase text-${theme}-500 font-bold mb-2 block tracking-widest`}>Max Value</label>
                              <input 
                                  type="text"
                                  inputMode={preferNativeKeyboard ? "decimal" : "none"}
                                  value={tempRange.max} 
                                  onChange={e => setTempRange(prev => ({...prev, max: e.target.value}))}
                                  onFocus={(e) => handleModalInputFocus(e, 'max')}
                                  className={`w-full bg-${theme}-900/50 p-4 text-white text-lg font-mono outline-none border-b-2 border-transparent focus:border-blue-500 transition-colors`}
                                  placeholder="100"
                                  autoFocus={activeModalInput === 'max'}
                              />
                          </div>
                      </div>
                      <div className={`flex border-t border-${theme}-900 -mx-6 -mb-6 ${uiConfig.headerHeightClass}`}>
                          {rangeConfigs[activeRangeModalVar] && (
                               <button onClick={removeSlider} className={`w-14 flex items-center justify-center border-r border-${theme}-900 text-red-500 hover:text-white hover:bg-red-900 transition-colors`}>
                                   <Trash2 className={uiConfig.iconClassName} />
                               </button>
                          )}
                          <button onClick={() => { setActiveRangeModalVar(null); setActiveModalInput(null); setShowKeyboard(false); }} className={`flex-1 bg-${theme}-950 text-${theme}-400 hover:text-white font-bold ${uiConfig.bodyClassName} uppercase tracking-widest hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}>Cancel</button>
                          <button onClick={saveRangeConfig} className={`flex-1 bg-blue-600 text-white hover:bg-blue-500 font-bold ${uiConfig.bodyClassName} uppercase tracking-widest transition-colors`}>Save</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Virtual Keyboard Overlay */}
      <div className={`fixed bottom-0 left-0 right-0 bg-${theme}-950 z-[60] transition-transform duration-200 ease-out pb-safe border-t border-${theme}-900 ${showKeyboard ? 'translate-y-0' : 'translate-y-full'}`}>
          {/* Hide Bar */}
          <div className={`flex justify-center items-center h-10 bg-${theme}-950 border-b border-${theme}-900`}>
              <button onClick={handleHideKeyboardTemp} className={`w-full h-full flex items-center justify-center text-${theme}-500 active:text-white`}>
                  <ChevronDown className={uiConfig.iconClassName} />
              </button>
          </div>

          {/* Grid */}
          <div className="grid grid-cols-4 gap-px bg-${theme}-900">
              {[1, 2, 3].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
               <button onPointerDown={handleDelDown} onPointerUp={handleDelUp} onPointerLeave={handleDelUp} onClick={(e) => e.preventDefault()} className={`h-[55px] bg-${theme}-950 text-xl font-medium text-red-500 active:bg-${theme}-900 flex items-center justify-center touch-none hover:bg-${theme}-900 transition-colors`}><Delete className="w-6 h-6" /></button>

              {[4, 5, 6].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
              <button onClick={() => handleVirtualInput('-')} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 flex items-center justify-center hover:bg-${theme}-900 transition-colors`}><Minus className="w-6 h-6" /></button>

              {[7, 8, 9].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
              <button onClick={() => handleVirtualInput('.')} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>.</button>

              <div className="col-span-2">
                  <button onClick={() => handleVirtualInput('0')} className={`h-[55px] w-full bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>0</button>
              </div>
              <div className="col-span-2">
                   <button onClick={() => handleVirtualInput('DONE')} className={`h-[55px] w-full bg-blue-600 text-white font-bold ${uiConfig.bodyClassName} uppercase tracking-widest active:bg-blue-500 flex items-center justify-center transition-colors`}>DONE</button>
              </div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Edit2, Info, Settings, Wrench, Plus, Minus, X } from 'lucide-react';
import { Formula } from '../types';

interface FormulaRunnerProps {
  formula: Formula;
  onBack: () => void;
  onEdit: () => void;
  onDelete: () => void;
  theme: string;
  uiConfig: any;
  onOpenSettings: () => void;
  onOpenDevTools: () => void;
}

interface RangeConfig {
  min: string;
  max: string;
  enabled: boolean;
  step?: string;
  precision?: number;
}

// --- Tile Component ---
interface RunnerTileProps {
    id: string;
    label: string;
    value: string;
    unit?: string;
    isResult?: boolean;
    isActive: boolean;
    rangeConfig?: RangeConfig;
    theme: string;
    uiConfig: any;
    onValueChange: (val: string) => void;
    onFocus: () => void;
    onToggleSliderConfig: () => void; // Triggered by Long Press +
}

const RunnerTile = ({ 
    id, label, value, unit, isResult, isActive, rangeConfig, 
    theme, uiConfig, onValueChange, onFocus, onToggleSliderConfig 
}: RunnerTileProps) => {
    const [localValue, setLocalValue] = useState(value);
    const minusTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const plusTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isLongPress = useRef(false);

    useEffect(() => {
        setLocalValue(value);
    }, [value]);

    const handleStep = (direction: 1 | -1) => {
        const current = parseFloat(localValue.replace(',', '.')) || 0;
        let step = 1;

        // Smart step based on existing decimals or range config
        if (rangeConfig?.step) {
            step = parseFloat(rangeConfig.step);
        } else if (localValue.includes('.') || localValue.includes(',')) {
            // Estimate precision
            const decimals = localValue.split(/[.,]/)[1]?.length || 0;
            if (decimals > 0) step = Math.pow(10, -decimals);
        }

        const next = current + (step * direction);

        // Round to avoid floating point errors
        const precision = rangeConfig?.precision || (step < 1 ? step.toString().split('.')[1].length : 0);
        const nextStr = next.toFixed(precision);

        onValueChange(nextStr);
    };

    // --- Interaction Handlers ---

    // Minus Button
    const handleMinusDown = () => {
        isLongPress.current = false;
        if (navigator.vibrate) navigator.vibrate(10);
        minusTimer.current = setTimeout(() => {
            isLongPress.current = true;
            if (navigator.vibrate) navigator.vibrate(50);
            onValueChange('0'); // Reset to 0
        }, 600);
    };

    const handleMinusUp = () => {
        if (minusTimer.current) clearTimeout(minusTimer.current);
        if (!isLongPress.current) {
            handleStep(-1);
        }
    };

    // Plus Button
    const handlePlusDown = () => {
        isLongPress.current = false;
        if (navigator.vibrate) navigator.vibrate(10);
        plusTimer.current = setTimeout(() => {
            isLongPress.current = true;
            if (navigator.vibrate) navigator.vibrate(50);
            onToggleSliderConfig(); // Open config / Enable slider
        }, 600);
    };

    const handlePlusUp = () => {
        if (plusTimer.current) clearTimeout(plusTimer.current);
        if (!isLongPress.current) {
            handleStep(1);
        }
    };

    const isSliderEnabled = rangeConfig?.enabled;
    const bgColor = isResult 
        ? `bg-indigo-950 border-indigo-900/50 text-indigo-100` 
        : `bg-${theme}-950 border-${theme}-900/50 text-${theme}-100`;

    const activeClass = isActive ? (isResult ? 'ring-1 ring-indigo-500' : `ring-1 ring-blue-500`) : '';

    return (
        <div className={`relative h-24 flex w-full mb-2 overflow-hidden rounded-xl border transition-all ${bgColor} ${activeClass}`}>

            {/* Left Button (-) */}
            <button
                onPointerDown={handleMinusDown}
                onPointerUp={handleMinusUp}
                onPointerLeave={() => { if(minusTimer.current) clearTimeout(minusTimer.current); }}
                className={`w-16 h-full flex items-center justify-center text-2xl font-bold bg-black/20 hover:bg-black/40 active:bg-black/60 transition-colors z-20 touch-none`}
            >
                <Minus className={uiConfig.iconClassName} />
            </button>

            {/* Center Area */}
            <div className="flex-1 relative flex flex-col items-center justify-center h-full">

                {/* Background Slider Track (Visual only unless interacting) */}
                {isSliderEnabled && (
                    <div className="absolute inset-0 z-0 opacity-20 bg-current overflow-hidden">
                         <div 
                            className={`h-full bg-white/30 origin-left transition-transform duration-75`}
                            style={{ 
                                transform: `scaleX(${Math.min(1, Math.max(0, (parseFloat(localValue) - parseFloat(rangeConfig.min)) / (parseFloat(rangeConfig.max) - parseFloat(rangeConfig.min))))})` 
                            }}
                         />
                    </div>
                )}

                {/* Top Label */}
                <div className={`absolute top-2 w-full text-center text-[10px] font-bold uppercase tracking-widest opacity-60 z-10 pointer-events-none`}>
                    {label}
                </div>

                {/* Main Value Input */}
                <div className="z-10 w-full px-2">
                    <input 
                        type="text"
                        inputMode="decimal"
                        value={localValue === '0' ? '' : localValue}
                        onChange={(e) => onValueChange(e.target.value)}
                        onFocus={onFocus}
                        placeholder="0"
                        className={`w-full text-center bg-transparent outline-none font-mono ${uiConfig.resultFontSize} font-bold leading-none placeholder-white/10`}
                    />
                </div>

                {/* Bottom Unit */}
                <div className={`absolute bottom-2 w-full text-center text-[10px] font-bold uppercase tracking-widest opacity-60 z-10 pointer-events-none`}>
                    {unit || '---'}
                </div>

                {/* Invisible Range Input Overlay for Gestures */}
                {isSliderEnabled && (
                    <input 
                        type="range"
                        min={rangeConfig.min}
                        max={rangeConfig.max}
                        step={rangeConfig.step || "1"}
                        value={parseFloat(localValue) || 0}
                        onChange={(e) => onValueChange(e.target.value)}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-30 touch-none"
                    />
                )}
            </div>

            {/* Right Button (+) */}
            <button
                onPointerDown={handlePlusDown}
                onPointerUp={handlePlusUp}
                onPointerLeave={() => { if(plusTimer.current) clearTimeout(plusTimer.current); }}
                className={`w-16 h-full flex items-center justify-center text-2xl font-bold bg-black/20 hover:bg-black/40 active:bg-black/60 transition-colors z-20 touch-none`}
            >
                <Plus className={uiConfig.iconClassName} />
            </button>
        </div>
    );
};

export const FormulaRunner: React.FC<FormulaRunnerProps> = ({ formula, onBack, onEdit, onDelete, theme, uiConfig, onOpenSettings, onOpenDevTools }) => {
  // Inputs & Calculation State
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [results, setResults] = useState<Record<string, string>>({});
  const [targetOutputId, setTargetOutputId] = useState<string | null>(null);

  // UI State
  const [showInfo, setShowInfo] = useState(false);
  const [isDeleteArmed, setIsDeleteArmed] = useState(false);
  const [activeField, setActiveField] = useState<string | null>(null);

  // Range State
  const [rangeConfigs, setRangeConfigs] = useState<Record<string, RangeConfig>>({});
  const [activeRangeModalVar, setActiveRangeModalVar] = useState<string | null>(null);
  const [tempRange, setTempRange] = useState({ min: '', max: '' });

  const [solvingVar, setSolvingVar] = useState<string>(formula.variables[0]?.symbol || '');
  const isReverseMode = targetOutputId !== null;

  // Persistence
  useEffect(() => {
    const savedInputs = localStorage.getItem(`calc_inputs_${formula.id}`);
    if (savedInputs) {
        try { setInputs(JSON.parse(savedInputs)); } catch (e) {}
    } else {
        const initial: Record<string, string> = {};
        formula.variables.forEach(v => initial[v.symbol] = v.defaultValue ? String(v.defaultValue) : '');
        setInputs(initial);
    }
    const savedRanges = localStorage.getItem(`calc_ranges_${formula.id}`);
    if (savedRanges) {
        try { setRangeConfigs(JSON.parse(savedRanges)); } catch (e) {}
    }
  }, [formula.id]);

  useEffect(() => {
     if (Object.keys(inputs).length > 0) localStorage.setItem(`calc_inputs_${formula.id}`, JSON.stringify(inputs));
  }, [inputs, formula.id]);

  useEffect(() => {
      localStorage.setItem(`calc_ranges_${formula.id}`, JSON.stringify(rangeConfigs));
  }, [rangeConfigs, formula.id]);

  // Math Logic
  const getNumericInputs = (currentInputs: Record<string, string>) => {
      const calcInputs: Record<string, number> = {};
      Object.keys(currentInputs).forEach(k => {
          const valStr = currentInputs[k].replace(',', '.');
          const val = valStr === '' || valStr === '-' ? 0 : parseFloat(valStr);
          calcInputs[k] = isNaN(val) ? 0 : val;
      });
      return calcInputs;
  };

  const evaluateExpression = (expression: string, numInputs: Record<string, number>) => {
      try {
          const names = Object.keys(numInputs);
          const values = Object.values(numInputs);
          const func = new Function(...names, `return (${expression});`);
          const res = func(...values);
          return isNaN(res) || !isFinite(res) ? 'Error' : res;
      } catch { return 'Error'; }
  };

  useEffect(() => {
    if (!isReverseMode) {
        const numInputs = getNumericInputs(inputs);
        const newResults: Record<string, string> = {};
        formula.outputs.forEach(output => {
            const res = evaluateExpression(output.expression, numInputs);
            newResults[output.id] = typeof res === 'number' ? String(Math.round(res * 10000) / 10000) : String(res);
        });
        setResults(newResults);
    }
  }, [inputs, formula.outputs, isReverseMode]);

  const solveForTarget = (targetVal: number, varSymbol: string, expression: string) => {
    let currentInputsNumeric = getNumericInputs(inputs);
    let x0 = currentInputsNumeric[varSymbol] || 1; 
    let x1 = x0 + 0.1;
    const maxIter = 50;
    const tolerance = 0.0001;
    const calc = (val: number) => {
        const temp = { ...currentInputsNumeric, [varSymbol]: val };
        const valRes = evaluateExpression(expression, temp);
        return typeof valRes === 'number' ? valRes : 0;
    };
    for (let i = 0; i < maxIter; i++) {
        const y0 = calc(x0);
        const y1 = calc(x1);
        if (Math.abs(y1 - targetVal) < tolerance) {
            setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
            return;
        }
        if (Math.abs(y1 - y0) < 1e-9) { x1 = x1 + Math.random(); continue; }
        const x_new = x1 - (y1 - targetVal) * (x1 - x0) / (y1 - y0);
        x0 = x1;
        x1 = x_new;
    }
    setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
  };

  const handleInputUpdate = (id: string, val: string, isOutput: boolean) => {
      if (isOutput) {
          // Goal Seek Mode
          setTargetOutputId(id);
          setResults(prev => ({...prev, [id]: val})); // Immediate visual update
          const num = parseFloat(val.replace(',', '.'));
          const targetOutput = formula.outputs.find(o => o.id === id);
          if (targetOutput && !isNaN(num) && solvingVar && val.trim() !== '' && val !== '-') {
              solveForTarget(num, solvingVar, targetOutput.expression);
          }
      } else {
          // Normal Input Mode
          setInputs(prev => ({...prev, [id]: val}));
          setTargetOutputId(null);
          // Auto-scale slider max
          if (rangeConfigs[id]?.enabled) {
              const numVal = parseFloat(val);
              if (!isNaN(numVal) && numVal > parseFloat(rangeConfigs[id].max)) {
                  setRangeConfigs(prev => ({...prev, [id]: { ...prev[id], max: val }}));
              }
          }
      }
  };

  // Range Config Handlers
  const handleOpenRangeConfig = (id: string, currentValue: string) => {
      setActiveRangeModalVar(id);
      const current = rangeConfigs[id];
      if (current) {
          setTempRange({ min: current.min, max: current.max });
      } else {
          // Default range logic
          const val = parseFloat(currentValue) || 0;
          setTempRange({ min: '0', max: val === 0 ? '100' : String(val * 2) });
      }
  };

  const saveRangeConfig = () => {
      if (activeRangeModalVar) {
          const minVal = parseFloat(tempRange.min);
          const maxVal = parseFloat(tempRange.max);
          if (!isNaN(minVal) && !isNaN(maxVal) && minVal < maxVal) {
              const minDec = tempRange.min.includes('.') ? tempRange.min.split('.')[1].length : 0;
              const maxDec = tempRange.max.includes('.') ? tempRange.max.split('.')[1].length : 0;
              const precision = Math.max(minDec, maxDec);
              const step = precision === 0 ? "1" : (1 / Math.pow(10, precision)).toFixed(precision);

              setRangeConfigs(prev => ({
                  ...prev,
                  [activeRangeModalVar]: {
                      min: tempRange.min,
                      max: tempRange.max,
                      enabled: true,
                      step: step,
                      precision: precision
                  }
              }));
          }
          setActiveRangeModalVar(null);
      }
  };

  const removeSlider = () => {
      if (activeRangeModalVar) {
          setRangeConfigs(prev => {
              const next = { ...prev };
              delete next[activeRangeModalVar];
              return next;
          });
          setActiveRangeModalVar(null);
      }
  };

  const handleDelete = () => {
      if (isDeleteArmed) { onDelete(); } else { setIsDeleteArmed(true); setTimeout(() => setIsDeleteArmed(false), 3000); }
  };

  return (
    <div className={`flex flex-col h-screen bg-${theme}-950 font-sans`}>

      {/* Header */}
      <div className={`flex items-center justify-center px-4 bg-${theme}-950 shrink-0 ${uiConfig.headerHeightClass} z-20 sticky top-0 border-b border-${theme}-900 relative`}>
          <div className="absolute left-4 flex gap-2">
            <button onClick={onOpenDevTools} className={`p-2 text-${theme}-600 hover:text-white transition-colors`}><Wrench className={uiConfig.iconClassName} /></button>
            <button onClick={onOpenSettings} className={`p-2 text-${theme}-600 hover:text-white transition-colors`}><Settings className={uiConfig.iconClassName} /></button>
          </div>
          <h1 className={`text-white font-bold ${uiConfig.headerClassName} truncate font-mono tracking-widest uppercase`}>{formula.title}</h1>
          <button onClick={handleDelete} className={`absolute right-4 p-2 transition-all rounded-full ${isDeleteArmed ? 'bg-red-900 text-white animate-pulse' : `text-${theme}-600 hover:text-red-400 hover:bg-${theme}-900`}`}>
              {isDeleteArmed ? <X className={uiConfig.iconClassName} /> : <Edit2 className={uiConfig.iconClassName} onClick={(e) => { e.stopPropagation(); onEdit(); }} />}
          </button>
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 overflow-y-auto p-4`}>

          {/* Target Selector (Goal Seek) - Shows when a result is being edited */}
          {targetOutputId && formula.variables.length > 0 && (
             <div className={`mb-4 p-3 bg-indigo-900/20 border border-indigo-900/50 rounded-xl flex items-center justify-between animate-fade-in`}>
                 <span className="text-indigo-400 text-xs font-bold uppercase tracking-widest">SOLVING FOR:</span>
                 <select 
                    value={solvingVar}
                    onChange={(e) => setSolvingVar(e.target.value)}
                    className={`bg-indigo-950 text-white text-sm font-bold uppercase outline-none px-2 py-1 rounded border border-indigo-900`}
                 >
                    {formula.variables.map(v => (
                        <option key={v.symbol} value={v.symbol}>{v.name || v.symbol}</option>
                    ))}
                 </select>
             </div>
          )}

          {/* Results Section */}
          <div className="mb-6 space-y-2">
              <div className="flex items-center gap-2 mb-2 px-1">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div>
                  <span className={`text-xs font-bold text-indigo-400 uppercase tracking-widest`}>Outputs</span>
              </div>
              {formula.outputs.map((output) => (
                  <RunnerTile 
                      key={output.id}
                      id={output.id}
                      label={output.name || "RESULT"}
                      value={results[output.id] || ''}
                      unit={output.unit}
                      isResult={true}
                      isActive={activeField === output.id}
                      rangeConfig={rangeConfigs[output.id]}
                      theme={theme}
                      uiConfig={uiConfig}
                      onValueChange={(val) => handleInputUpdate(output.id, val, true)}
                      onFocus={() => { setActiveField(output.id); setTargetOutputId(output.id); }}
                      onToggleSliderConfig={() => handleOpenRangeConfig(output.id, results[output.id] || '0')}
                  />
              ))}
          </div>

          {/* Variables Section */}
          <div className="space-y-2">
              <div className="flex items-center gap-2 mb-2 px-1">
                  <div className={`w-1.5 h-1.5 rounded-full bg-${theme}-500`}></div>
                  <span className={`text-xs font-bold text-${theme}-400 uppercase tracking-widest`}>Inputs</span>
              </div>
              {formula.variables.map((v) => (
                  <RunnerTile 
                      key={v.id}
                      id={v.symbol}
                      label={v.name || v.symbol}
                      value={inputs[v.symbol] || ''}
                      unit={v.unit}
                      isResult={false}
                      isActive={activeField === v.symbol}
                      rangeConfig={rangeConfigs[v.symbol]}
                      theme={theme}
                      uiConfig={uiConfig}
                      onValueChange={(val) => handleInputUpdate(v.symbol, val, false)}
                      onFocus={() => { setActiveField(v.symbol); }}
                      onToggleSliderConfig={() => handleOpenRangeConfig(v.symbol, inputs[v.symbol] || '0')}
                  />
              ))}
          </div>

          {/* Reset Button */}
          <div className="mt-8 flex justify-center pb-8">
             <button 
                onClick={() => {
                    const initial: Record<string, string> = {};
                    formula.variables.forEach(v => { initial[v.symbol] = ''; });
                    setInputs(initial);
                    setTargetOutputId(null);
                    setResults({});
                    localStorage.removeItem(`calc_inputs_${formula.id}`);
                }}
                className={`text-${theme}-600 hover:text-white transition-colors p-4 rounded-full bg-${theme}-900/30 hover:bg-${theme}-900`}
             >
                <RotateCcw className={uiConfig.iconClassName} />
             </button>
          </div>
      </div>

      {/* Footer (Back Only) */}
      <div className={`bg-${theme}-950 border-t border-${theme}-900 p-0 z-30 flex ${uiConfig.headerHeightClass} safe-area-pb`}>
            <button 
                onClick={onBack}
                className={`w-full flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors`}
            >
                <ArrowLeft className={uiConfig.iconClassName} />
            </button>
      </div>

      {/* Range Config Modal */}
      {activeRangeModalVar && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-sm animate-fade-in p-0">
              <div className={`bg-${theme}-950 w-full max-w-xs shadow-2xl border border-${theme}-900 rounded-xl overflow-hidden`}>
                  <div className={`h-12 flex items-center px-4 border-b border-${theme}-900 bg-${theme}-900/30`}>
                    <h3 className={`text-white text-xs font-bold font-mono uppercase tracking-widest`}>
                        Slider Config
                    </h3>
                  </div>
                  <div className="p-4">
                      <div className="flex gap-3 mb-4">
                          <div className="flex-1">
                              <label className={`text-[10px] uppercase text-${theme}-500 font-bold mb-1 block tracking-widest`}>Min</label>
                              <input 
                                  type="text"
                                  inputMode="decimal"
                                  value={tempRange.min} 
                                  onChange={e => setTempRange(prev => ({...prev, min: e.target.value}))}
                                  className={`w-full bg-${theme}-900/50 p-2 text-white text-sm font-mono outline-none rounded border border-transparent focus:border-blue-500`}
                              />
                          </div>
                          <div className="flex-1">
                              <label className={`text-[10px] uppercase text-${theme}-500 font-bold mb-1 block tracking-widest`}>Max</label>
                              <input 
                                  type="text"
                                  inputMode="decimal"
                                  value={tempRange.max} 
                                  onChange={e => setTempRange(prev => ({...prev, max: e.target.value}))}
                                  className={`w-full bg-${theme}-900/50 p-2 text-white text-sm font-mono outline-none rounded border border-transparent focus:border-blue-500`}
                              />
                          </div>
                      </div>
                      <div className={`flex gap-2`}>
                          {rangeConfigs[activeRangeModalVar] && (
                               <button onClick={removeSlider} className={`px-4 bg-red-900/30 text-red-500 hover:text-white hover:bg-red-900 rounded font-bold uppercase text-xs`}>
                                   Disable
                               </button>
                          )}
                          <button onClick={() => setActiveRangeModalVar(null)} className={`flex-1 py-3 bg-${theme}-900 text-${theme}-400 hover:text-white font-bold uppercase text-xs tracking-widest rounded`}>Cancel</button>
                          <button onClick={saveRangeConfig} className={`flex-1 py-3 bg-blue-600 text-white hover:bg-blue-500 font-bold uppercase text-xs tracking-widest rounded`}>Save</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Edit2, Info, Settings, Wrench, Plus, Minus, X, RotateCcw } from 'lucide-react';
import { Formula } from '../types';

interface FormulaRunnerProps {
  formula: Formula;
  onBack: () => void;
  onEdit: () => void;
  onDelete: () => void;
  theme: string;
  uiConfig: any;
  onOpenSettings: () => void;
  onOpenDevTools: () => void;
}

interface RangeConfig {
  min: string;
  max: string;
  enabled: boolean;
  step?: string;
  precision?: number;
}

// --- Tile Component ---
interface RunnerTileProps {
    id: string;
    label: string;
    value: string;
    unit?: string;
    isResult?: boolean;
    isActive: boolean;
    rangeConfig?: RangeConfig;
    theme: string;
    uiConfig: any;
    onValueChange: (val: string) => void;
    onFocus: () => void;
    onToggleSliderConfig: () => void; // Triggered by Long Press +
}

const RunnerTile: React.FC<RunnerTileProps> = ({ 
    id, label, value, unit, isResult, isActive, rangeConfig, 
    theme, uiConfig, onValueChange, onFocus, onToggleSliderConfig 
}) => {
    const [localValue, setLocalValue] = useState(value);
    const minusTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const plusTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isLongPress = useRef(false);

    useEffect(() => {
        setLocalValue(value);
    }, [value]);

    const handleStep = (direction: 1 | -1) => {
        const current = parseFloat(localValue.replace(',', '.')) || 0;
        let step = 1;

        // Smart step based on existing decimals or range config
        if (rangeConfig?.step) {
            step = parseFloat(rangeConfig.step);
        } else if (localValue.includes('.') || localValue.includes(',')) {
            // Estimate precision
            const decimals = localValue.split(/[.,]/)[1]?.length || 0;
            if (decimals > 0) step = Math.pow(10, -decimals);
        }

        const next = current + (step * direction);

        // Round to avoid floating point errors
        const precision = rangeConfig?.precision || (step < 1 ? step.toString().split('.')[1].length : 0);
        const nextStr = next.toFixed(precision);

        onValueChange(nextStr);
    };

    // --- Interaction Handlers ---

    // Minus Button
    const handleMinusDown = () => {
        isLongPress.current = false;
        if (navigator.vibrate) navigator.vibrate(10);
        minusTimer.current = setTimeout(() => {
            isLongPress.current = true;
            if (navigator.vibrate) navigator.vibrate(50);
            onValueChange('0'); // Reset to 0
        }, 600);
    };

    const handleMinusUp = () => {
        if (minusTimer.current) clearTimeout(minusTimer.current);
        if (!isLongPress.current) {
            handleStep(-1);
        }
    };

    // Plus Button
    const handlePlusDown = () => {
        isLongPress.current = false;
        if (navigator.vibrate) navigator.vibrate(10);
        plusTimer.current = setTimeout(() => {
            isLongPress.current = true;
            if (navigator.vibrate) navigator.vibrate(50);
            onToggleSliderConfig(); // Open config / Enable slider
        }, 600);
    };

    const handlePlusUp = () => {
        if (plusTimer.current) clearTimeout(plusTimer.current);
        if (!isLongPress.current) {
            handleStep(1);
        }
    };

    const isSliderEnabled = rangeConfig?.enabled;
    const bgColor = isResult 
        ? `bg-indigo-950 border-indigo-900/50 text-indigo-100` 
        : `bg-${theme}-950 border-${theme}-900/50 text-${theme}-100`;

    const activeClass = isActive ? (isResult ? 'ring-1 ring-indigo-500' : `ring-1 ring-blue-500`) : '';

    return (
        <div className={`relative h-24 flex w-full mb-2 overflow-hidden rounded-xl border transition-all ${bgColor} ${activeClass}`}>

            {/* Left Button (-) */}
            <button
                onPointerDown={handleMinusDown}
                onPointerUp={handleMinusUp}
                onPointerLeave={() => { if(minusTimer.current) clearTimeout(minusTimer.current); }}
                className={`w-16 h-full flex items-center justify-center text-2xl font-bold bg-black/20 hover:bg-black/40 active:bg-black/60 transition-colors z-20 touch-none`}
            >
                <Minus className={uiConfig.iconClassName} />
            </button>

            {/* Center Area */}
            <div className="flex-1 relative flex flex-col items-center justify-center h-full">

                {/* Background Slider Track (Visual only unless interacting) */}
                {isSliderEnabled && rangeConfig && (
                    <div className="absolute inset-0 z-0 opacity-20 bg-current overflow-hidden">
                         <div 
                            className={`h-full bg-white/30 origin-left transition-transform duration-75`}
                            style={{ 
                                transform: `scaleX(${Math.min(1, Math.max(0, (parseFloat(localValue) - parseFloat(rangeConfig.min)) / (parseFloat(rangeConfig.max) - parseFloat(rangeConfig.min))))})` 
                            }}
                         />
                    </div>
                )}

                {/* Top Label */}
                <div className={`absolute top-2 w-full text-center text-[10px] font-bold uppercase tracking-widest opacity-60 z-10 pointer-events-none`}>
                    {label}
                </div>

                {/* Main Value Input */}
                <div className="z-10 w-full px-2">
                    <input 
                        type="text"
                        inputMode="decimal"
                        value={localValue === '0' ? '' : localValue}
                        onChange={(e) => onValueChange(e.target.value)}
                        onFocus={onFocus}
                        placeholder="0"
                        className={`w-full text-center bg-transparent outline-none font-mono ${uiConfig.resultFontSize} font-bold leading-none placeholder-white/10`}
                    />
                </div>

                {/* Bottom Unit */}
                <div className={`absolute bottom-2 w-full text-center text-[10px] font-bold uppercase tracking-widest opacity-60 z-10 pointer-events-none`}>
                    {unit || '---'}
                </div>

                {/* Invisible Range Input Overlay for Gestures */}
                {isSliderEnabled && rangeConfig && (
                    <input 
                        type="range"
                        min={rangeConfig.min}
                        max={rangeConfig.max}
                        step={rangeConfig.step || "1"}
                        value={parseFloat(localValue) || 0}
                        onChange={(e) => onValueChange(e.target.value)}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-30 touch-none"
                    />
                )}
            </div>

            {/* Right Button (+) */}
            <button
                onPointerDown={handlePlusDown}
                onPointerUp={handlePlusUp}
                onPointerLeave={() => { if(plusTimer.current) clearTimeout(plusTimer.current); }}
                className={`w-16 h-full flex items-center justify-center text-2xl font-bold bg-black/20 hover:bg-black/40 active:bg-black/60 transition-colors z-20 touch-none`}
            >
                <Plus className={uiConfig.iconClassName} />
            </button>
        </div>
    );
};

export const FormulaRunner: React.FC<FormulaRunnerProps> = ({ formula, onBack, onEdit, onDelete, theme, uiConfig, onOpenSettings, onOpenDevTools }) => {
  // Inputs & Calculation State
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [results, setResults] = useState<Record<string, string>>({});
  const [targetOutputId, setTargetOutputId] = useState<string | null>(null);

  // UI State
  const [showInfo, setShowInfo] = useState(false);
  const [isDeleteArmed, setIsDeleteArmed] = useState(false);
  const [activeField, setActiveField] = useState<string | null>(null);

  // Range State
  const [rangeConfigs, setRangeConfigs] = useState<Record<string, RangeConfig>>({});
  const [activeRangeModalVar, setActiveRangeModalVar] = useState<string | null>(null);
  const [tempRange, setTempRange] = useState({ min: '', max: '' });

  const [solvingVar, setSolvingVar] = useState<string>(formula.variables[0]?.symbol || '');
  const isReverseMode = targetOutputId !== null;

  // Persistence
  useEffect(() => {
    const savedInputs = localStorage.getItem(`calc_inputs_${formula.id}`);
    if (savedInputs) {
        try { setInputs(JSON.parse(savedInputs)); } catch (e) {}
    } else {
        const initial: Record<string, string> = {};
        formula.variables.forEach(v => initial[v.symbol] = v.defaultValue ? String(v.defaultValue) : '');
        setInputs(initial);
    }
    const savedRanges = localStorage.getItem(`calc_ranges_${formula.id}`);
    if (savedRanges) {
        try { setRangeConfigs(JSON.parse(savedRanges)); } catch (e) {}
    }
  }, [formula.id]);

  useEffect(() => {
     if (Object.keys(inputs).length > 0) localStorage.setItem(`calc_inputs_${formula.id}`, JSON.stringify(inputs));
  }, [inputs, formula.id]);

  useEffect(() => {
      localStorage.setItem(`calc_ranges_${formula.id}`, JSON.stringify(rangeConfigs));
  }, [rangeConfigs, formula.id]);

  // Math Logic
  const getNumericInputs = (currentInputs: Record<string, string>) => {
      const calcInputs: Record<string, number> = {};
      Object.keys(currentInputs).forEach(k => {
          const valStr = currentInputs[k].replace(',', '.');
          const val = valStr === '' || valStr === '-' ? 0 : parseFloat(valStr);
          calcInputs[k] = isNaN(val) ? 0 : val;
      });
      return calcInputs;
  };

  const evaluateExpression = (expression: string, numInputs: Record<string, number>) => {
      try {
          const names = Object.keys(numInputs);
          const values = Object.values(numInputs);
          const func = new Function(...names, `return (${expression});`);
          const res = func(...values);
          return isNaN(res) || !isFinite(res) ? 'Error' : res;
      } catch { return 'Error'; }
  };

  useEffect(() => {
    if (!isReverseMode) {
        const numInputs = getNumericInputs(inputs);
        const newResults: Record<string, string> = {};
        formula.outputs.forEach(output => {
            const res = evaluateExpression(output.expression, numInputs);
            newResults[output.id] = typeof res === 'number' ? String(Math.round(res * 10000) / 10000) : String(res);
        });
        setResults(newResults);
    }
  }, [inputs, formula.outputs, isReverseMode]);

  const solveForTarget = (targetVal: number, varSymbol: string, expression: string) => {
    let currentInputsNumeric = getNumericInputs(inputs);
    let x0 = currentInputsNumeric[varSymbol] || 1; 
    let x1 = x0 + 0.1;
    const maxIter = 50;
    const tolerance = 0.0001;
    const calc = (val: number) => {
        const temp = { ...currentInputsNumeric, [varSymbol]: val };
        const valRes = evaluateExpression(expression, temp);
        return typeof valRes === 'number' ? valRes : 0;
    };
    for (let i = 0; i < maxIter; i++) {
        const y0 = calc(x0);
        const y1 = calc(x1);
        if (Math.abs(y1 - targetVal) < tolerance) {
            setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
            return;
        }
        if (Math.abs(y1 - y0) < 1e-9) { x1 = x1 + Math.random(); continue; }
        const x_new = x1 - (y1 - targetVal) * (x1 - x0) / (y1 - y0);
        x0 = x1;
        x1 = x_new;
    }
    setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
  };

  const handleInputUpdate = (id: string, val: string, isOutput: boolean) => {
      if (isOutput) {
          // Goal Seek Mode
          setTargetOutputId(id);
          setResults(prev => ({...prev, [id]: val})); // Immediate visual update
          const num = parseFloat(val.replace(',', '.'));
          const targetOutput = formula.outputs.find(o => o.id === id);
          if (targetOutput && !isNaN(num) && solvingVar && val.trim() !== '' && val !== '-') {
              solveForTarget(num, solvingVar, targetOutput.expression);
          }
      } else {
          // Normal Input Mode
          setInputs(prev => ({...prev, [id]: val}));
          setTargetOutputId(null);
          // Auto-scale slider max
          if (rangeConfigs[id]?.enabled) {
              const numVal = parseFloat(val);
              if (!isNaN(numVal) && numVal > parseFloat(rangeConfigs[id].max)) {
                  setRangeConfigs(prev => ({...prev, [id]: { ...prev[id], max: val }}));
              }
          }
      }
  };

  // Range Config Handlers
  const handleOpenRangeConfig = (id: string, currentValue: string) => {
      setActiveRangeModalVar(id);
      const current = rangeConfigs[id];
      if (current) {
          setTempRange({ min: current.min, max: current.max });
      } else {
          // Default range logic
          const val = parseFloat(currentValue) || 0;
          setTempRange({ min: '0', max: val === 0 ? '100' : String(val * 2) });
      }
  };

  const saveRangeConfig = () => {
      if (activeRangeModalVar) {
          const minVal = parseFloat(tempRange.min);
          const maxVal = parseFloat(tempRange.max);
          if (!isNaN(minVal) && !isNaN(maxVal) && minVal < maxVal) {
              const minDec = tempRange.min.includes('.') ? tempRange.min.split('.')[1].length : 0;
              const maxDec = tempRange.max.includes('.') ? tempRange.max.split('.')[1].length : 0;
              const precision = Math.max(minDec, maxDec);
              const step = precision === 0 ? "1" : (1 / Math.pow(10, precision)).toFixed(precision);

              setRangeConfigs(prev => ({
                  ...prev,
                  [activeRangeModalVar]: {
                      min: tempRange.min,
                      max: tempRange.max,
                      enabled: true,
                      step: step,
                      precision: precision
                  }
              }));
          }
          setActiveRangeModalVar(null);
      }
  };

  const removeSlider = () => {
      if (activeRangeModalVar) {
          setRangeConfigs(prev => {
              const next = { ...prev };
              delete next[activeRangeModalVar];
              return next;
          });
          setActiveRangeModalVar(null);
      }
  };

  const handleDelete = () => {
      if (isDeleteArmed) { onDelete(); } else { setIsDeleteArmed(true); setTimeout(() => setIsDeleteArmed(false), 3000); }
  };

  return (
    <div className={`flex flex-col h-screen bg-${theme}-950 font-sans`}>

      {/* Header */}
      <div className={`flex items-center justify-center px-4 bg-${theme}-950 shrink-0 ${uiConfig.headerHeightClass} z-20 sticky top-0 border-b border-${theme}-900 relative`}>
          <div className="absolute left-4 flex gap-2">
            <button onClick={onOpenDevTools} className={`p-2 text-${theme}-600 hover:text-white transition-colors`}><Wrench className={uiConfig.iconClassName} /></button>
            <button onClick={onOpenSettings} className={`p-2 text-${theme}-600 hover:text-white transition-colors`}><Settings className={uiConfig.iconClassName} /></button>
          </div>
          <h1 className={`text-white font-bold ${uiConfig.headerClassName} truncate font-mono tracking-widest uppercase`}>{formula.title}</h1>
          <button onClick={handleDelete} className={`absolute right-4 p-2 transition-all rounded-full ${isDeleteArmed ? 'bg-red-900 text-white animate-pulse' : `text-${theme}-600 hover:text-red-400 hover:bg-${theme}-900`}`}>
              {isDeleteArmed ? <X className={uiConfig.iconClassName} /> : <Edit2 className={uiConfig.iconClassName} onClick={(e) => { e.stopPropagation(); onEdit(); }} />}
          </button>
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 overflow-y-auto p-4`}>

          {/* Target Selector (Goal Seek) - Shows when a result is being edited */}
          {targetOutputId && formula.variables.length > 0 && (
             <div className={`mb-4 p-3 bg-indigo-900/20 border border-indigo-900/50 rounded-xl flex items-center justify-between animate-fade-in`}>
                 <span className="text-indigo-400 text-xs font-bold uppercase tracking-widest">SOLVING FOR:</span>
                 <select 
                    value={solvingVar}
                    onChange={(e) => setSolvingVar(e.target.value)}
                    className={`bg-indigo-950 text-white text-sm font-bold uppercase outline-none px-2 py-1 rounded border border-indigo-900`}
                 >
                    {formula.variables.map(v => (
                        <option key={v.symbol} value={v.symbol}>{v.name || v.symbol}</option>
                    ))}
                 </select>
             </div>
          )}

          {/* Results Section */}
          <div className="mb-6 space-y-2">
              <div className="flex items-center gap-2 mb-2 px-1">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div>
                  <span className={`text-xs font-bold text-indigo-400 uppercase tracking-widest`}>Outputs</span>
              </div>
              {formula.outputs.map((output) => (
                  <RunnerTile 
                      key={output.id}
                      id={output.id}
                      label={output.name || "RESULT"}
                      value={results[output.id] || ''}
                      unit={output.unit}
                      isResult={true}
                      isActive={activeField === output.id}
                      rangeConfig={rangeConfigs[output.id]}
                      theme={theme}
                      uiConfig={uiConfig}
                      onValueChange={(val) => handleInputUpdate(output.id, val, true)}
                      onFocus={() => { setActiveField(output.id); setTargetOutputId(output.id); }}
                      onToggleSliderConfig={() => handleOpenRangeConfig(output.id, results[output.id] || '0')}
                  />
              ))}
          </div>

          {/* Variables Section */}
          <div className="space-y-2">
              <div className="flex items-center gap-2 mb-2 px-1">
                  <div className={`w-1.5 h-1.5 rounded-full bg-${theme}-500`}></div>
                  <span className={`text-xs font-bold text-${theme}-400 uppercase tracking-widest`}>Inputs</span>
              </div>
              {formula.variables.map((v) => (
                  <RunnerTile 
                      key={v.id}
                      id={v.symbol}
                      label={v.name || v.symbol}
                      value={inputs[v.symbol] || ''}
                      unit={v.unit}
                      isResult={false}
                      isActive={activeField === v.symbol}
                      rangeConfig={rangeConfigs[v.symbol]}
                      theme={theme}
                      uiConfig={uiConfig}
                      onValueChange={(val) => handleInputUpdate(v.symbol, val, false)}
                      onFocus={() => { setActiveField(v.symbol); }}
                      onToggleSliderConfig={() => handleOpenRangeConfig(v.symbol, inputs[v.symbol] || '0')}
                  />
              ))}
          </div>

          {/* Reset Button */}
          <div className="mt-8 flex justify-center pb-8">
             <button 
                onClick={() => {
                    const initial: Record<string, string> = {};
                    formula.variables.forEach(v => { initial[v.symbol] = ''; });
                    setInputs(initial);
                    setTargetOutputId(null);
                    setResults({});
                    localStorage.removeItem(`calc_inputs_${formula.id}`);
                }}
                className={`text-${theme}-600 hover:text-white transition-colors p-4 rounded-full bg-${theme}-900/30 hover:bg-${theme}-900`}
             >
                <RotateCcw className={uiConfig.iconClassName} />
             </button>
          </div>
      </div>

      {/* Footer (Back Only) */}
      <div className={`bg-${theme}-950 border-t border-${theme}-900 p-0 z-30 flex ${uiConfig.headerHeightClass} safe-area-pb`}>
            <button 
                onClick={onBack}
                className={`w-full flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors`}
            >
                <ArrowLeft className={uiConfig.iconClassName} />
            </button>
      </div>

      {/* Range Config Modal */}
      {activeRangeModalVar && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-sm animate-fade-in p-0">
              <div className={`bg-${theme}-950 w-full max-w-xs shadow-2xl border border-${theme}-900 rounded-xl overflow-hidden`}>
                  <div className={`h-12 flex items-center px-4 border-b border-${theme}-900 bg-${theme}-900/30`}>
                    <h3 className={`text-white text-xs font-bold font-mono uppercase tracking-widest`}>
                        Slider Config
                    </h3>
                  </div>
                  <div className="p-4">
                      <div className="flex gap-3 mb-4">
                          <div className="flex-1">
                              <label className={`text-[10px] uppercase text-${theme}-500 font-bold mb-1 block tracking-widest`}>Min</label>
                              <input 
                                  type="text"
                                  inputMode="decimal"
                                  value={tempRange.min} 
                                  onChange={e => setTempRange(prev => ({...prev, min: e.target.value}))}
                                  className={`w-full bg-${theme}-900/50 p-2 text-white text-sm font-mono outline-none rounded border border-transparent focus:border-blue-500`}
                              />
                          </div>
                          <div className="flex-1">
                              <label className={`text-[10px] uppercase text-${theme}-500 font-bold mb-1 block tracking-widest`}>Max</label>
                              <input 
                                  type="text"
                                  inputMode="decimal"
                                  value={tempRange.max} 
                                  onChange={e => setTempRange(prev => ({...prev, max: e.target.value}))}
                                  className={`w-full bg-${theme}-900/50 p-2 text-white text-sm font-mono outline-none rounded border border-transparent focus:border-blue-500`}
                              />
                          </div>
                      </div>
                      <div className={`flex gap-2`}>
                          {rangeConfigs[activeRangeModalVar] && (
                               <button onClick={removeSlider} className={`px-4 bg-red-900/30 text-red-500 hover:text-white hover:bg-red-900 rounded font-bold uppercase text-xs`}>
                                   Disable
                               </button>
                          )}
                          <button onClick={() => setActiveRangeModalVar(null)} className={`flex-1 py-3 bg-${theme}-900 text-${theme}-400 hover:text-white font-bold uppercase text-xs tracking-widest rounded`}>Cancel</button>
                          <button onClick={saveRangeConfig} className={`flex-1 py-3 bg-blue-600 text-white hover:bg-blue-500 font-bold uppercase text-xs tracking-widest rounded`}>Save</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Edit2, Info, Settings, Wrench, Plus, Minus, X, RotateCcw, Keyboard, ChevronDown, Delete, Copy, ArrowRightLeft } from 'lucide-react';
import { Formula } from '../types';

interface FormulaRunnerProps {
  formula: Formula;
  onBack: () => void;
  onEdit: () => void;
  onDelete: () => void;
  theme: string;
  uiConfig: any;
  onOpenSettings: () => void;
  onOpenDevTools: () => void;
}

interface RangeConfig {
  min: string;
  max: string;
  enabled: boolean;
  step?: string;
  precision?: number;
}

// --- Tile Component ---
interface RunnerTileProps {
    id: string;
    label: string;
    value: string;
    unit?: string;
    isResult?: boolean;
    isActive: boolean;
    rangeConfig?: RangeConfig;
    theme: string;
    uiConfig: any;
    onValueChange: (val: string) => void;
    onFocus: () => void;
    onToggleSliderConfig: () => void;
    onReset: () => void;
}

const RunnerTile: React.FC<RunnerTileProps> = ({ 
    id, label, value, unit, isResult, isActive, rangeConfig, 
    theme, uiConfig, onValueChange, onFocus, onToggleSliderConfig, onReset 
}) => {
    const [localValue, setLocalValue] = useState(value);
    const minusTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const plusTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isLongPress = useRef(false);

    useEffect(() => {
        setLocalValue(value);
    }, [value]);

    const handleStep = (direction: 1 | -1) => {
        const current = parseFloat(localValue.replace(',', '.')) || 0;
        let step = 1;

        if (rangeConfig?.step) {
            step = parseFloat(rangeConfig.step);
        } else if (localValue.includes('.') || localValue.includes(',')) {
            const decimals = localValue.split(/[.,]/)[1]?.length || 0;
            if (decimals > 0) step = Math.pow(10, -decimals);
        }

        const next = current + (step * direction);
        const precision = rangeConfig?.precision || (step < 1 ? step.toString().split('.')[1].length : 0);
        const nextStr = next.toFixed(precision);

        onValueChange(nextStr);
    };

    // --- Interaction Handlers ---

    // Minus Button
    const handleMinusDown = () => {
        isLongPress.current = false;
        if (navigator.vibrate) navigator.vibrate(10);
        minusTimer.current = setTimeout(() => {
            isLongPress.current = true;
            if (navigator.vibrate) navigator.vibrate(50);
            onReset(); // Reset to 0
        }, 600);
    };

    const handleMinusUp = () => {
        if (minusTimer.current) clearTimeout(minusTimer.current);
        if (!isLongPress.current) {
            handleStep(-1);
        }
    };

    // Plus Button
    const handlePlusDown = () => {
        isLongPress.current = false;
        if (navigator.vibrate) navigator.vibrate(10);
        plusTimer.current = setTimeout(() => {
            isLongPress.current = true;
            if (navigator.vibrate) navigator.vibrate(50);
            onToggleSliderConfig(); // Open config / Enable slider
        }, 600);
    };

    const handlePlusUp = () => {
        if (plusTimer.current) clearTimeout(plusTimer.current);
        if (!isLongPress.current) {
            handleStep(1);
        }
    };

    const isSliderEnabled = rangeConfig?.enabled;

    // Aesthetic Logic
    // Using rounded-3xl for pill shape
    // Background colors differ slightly for Result vs Input
    const containerClass = isResult 
        ? `bg-indigo-950/80 border-indigo-500/30 text-indigo-100` 
        : `bg-${theme}-950 border-${theme}-800 text-${theme}-100`;

    const activeClass = isActive 
        ? (isResult ? 'ring-2 ring-indigo-500 border-transparent' : `ring-2 ring-blue-500 border-transparent`) 
        : 'border';

    // Slider Indicator Position
    let sliderPercent = 0;
    if (isSliderEnabled && rangeConfig) {
        const min = parseFloat(rangeConfig.min);
        const max = parseFloat(rangeConfig.max);
        const val = parseFloat(localValue) || 0;
        if (max > min) {
            sliderPercent = Math.min(100, Math.max(0, ((val - min) / (max - min)) * 100));
        }
    }

    return (
        <div className={`relative h-24 flex w-full mb-3 overflow-hidden rounded-[2rem] transition-all shadow-lg ${containerClass} ${activeClass}`}>

            {/* Left Button (-) */}
            <button
                onPointerDown={handleMinusDown}
                onPointerUp={handleMinusUp}
                onPointerLeave={() => { if(minusTimer.current) clearTimeout(minusTimer.current); }}
                className={`w-16 h-full flex items-center justify-center text-3xl pb-1 font-light bg-black/20 hover:bg-black/40 active:bg-black/60 transition-colors z-20 touch-none select-none`}
            >
                <Minus className="w-6 h-6" strokeWidth={3} />
            </button>

            {/* Center Area */}
            <div className="flex-1 relative flex flex-col items-center justify-center h-full group" onClick={onFocus}>

                {/* Vertical Blue Line Indicator (Old Style) */}
                {isSliderEnabled && rangeConfig && (
                    <div className="absolute inset-y-0 w-full z-0 pointer-events-none opacity-50">
                         <div 
                            className={`absolute top-0 bottom-0 w-1 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.8)] transition-all duration-75 ease-out`}
                            style={{ left: `${sliderPercent}%` }}
                         />
                    </div>
                )}

                {/* Top Label */}
                <div className={`absolute top-3 w-full text-center text-[10px] font-bold uppercase tracking-[0.2em] opacity-50 z-10 pointer-events-none truncate px-2`}>
                    {label}
                </div>

                {/* Main Value Input */}
                <div className="z-10 w-full px-2 relative">
                    <input 
                        type="text"
                        inputMode="decimal"
                        value={localValue === '0' ? '' : localValue}
                        onChange={(e) => onValueChange(e.target.value)}
                        onFocus={onFocus}
                        placeholder="0"
                        className={`w-full text-center bg-transparent outline-none font-sans text-3xl font-medium leading-none placeholder-white/10 drop-shadow-md`}
                    />
                </div>

                {/* Bottom Unit */}
                <div className={`absolute bottom-3 w-full text-center text-[10px] font-bold uppercase tracking-[0.1em] opacity-50 z-10 pointer-events-none`}>
                    {unit || ''}
                </div>

                {/* Invisible Range Input Overlay for Gestures */}
                {isSliderEnabled && rangeConfig && (
                    <input 
                        type="range"
                        min={rangeConfig.min}
                        max={rangeConfig.max}
                        step={rangeConfig.step || "1"}
                        value={parseFloat(localValue) || 0}
                        onChange={(e) => onValueChange(e.target.value)}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-30 touch-none"
                    />
                )}
            </div>

            {/* Right Button (+) */}
            <button
                onPointerDown={handlePlusDown}
                onPointerUp={handlePlusUp}
                onPointerLeave={() => { if(plusTimer.current) clearTimeout(plusTimer.current); }}
                className={`w-16 h-full flex items-center justify-center text-3xl pb-1 font-light bg-black/20 hover:bg-black/40 active:bg-black/60 transition-colors z-20 touch-none select-none`}
            >
                <Plus className="w-6 h-6" strokeWidth={3} />
            </button>
        </div>
    );
};

export const FormulaRunner: React.FC<FormulaRunnerProps> = ({ formula, onBack, onEdit, onDelete, theme, uiConfig, onOpenSettings, onOpenDevTools }) => {
  // Inputs & Calculation State
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [results, setResults] = useState<Record<string, string>>({});
  const [targetOutputId, setTargetOutputId] = useState<string | null>(null);

  // UI State
  const [showInfo, setShowInfo] = useState(false);
  const [showKeyboard, setShowKeyboard] = useState(false);
  const [preferNativeKeyboard, setPreferNativeKeyboard] = useState(false);
  const [activeField, setActiveField] = useState<string | null>(null);

  // Range State
  const [rangeConfigs, setRangeConfigs] = useState<Record<string, RangeConfig>>({});
  const [activeRangeModalVar, setActiveRangeModalVar] = useState<string | null>(null);
  const [tempRange, setTempRange] = useState({ min: '', max: '' });

  const [solvingVar, setSolvingVar] = useState<string>(formula.variables[0]?.symbol || '');
  const isReverseMode = targetOutputId !== null;

  // Persistence
  useEffect(() => {
    const savedInputs = localStorage.getItem(`calc_inputs_${formula.id}`);
    if (savedInputs) {
        try { setInputs(JSON.parse(savedInputs)); } catch (e) {}
    } else {
        const initial: Record<string, string> = {};
        formula.variables.forEach(v => initial[v.symbol] = v.defaultValue ? String(v.defaultValue) : '');
        setInputs(initial);
    }
    const savedRanges = localStorage.getItem(`calc_ranges_${formula.id}`);
    if (savedRanges) {
        try { setRangeConfigs(JSON.parse(savedRanges)); } catch (e) {}
    }
  }, [formula.id]);

  useEffect(() => {
     if (Object.keys(inputs).length > 0) localStorage.setItem(`calc_inputs_${formula.id}`, JSON.stringify(inputs));
  }, [inputs, formula.id]);

  useEffect(() => {
      localStorage.setItem(`calc_ranges_${formula.id}`, JSON.stringify(rangeConfigs));
  }, [rangeConfigs, formula.id]);

  // Math Logic
  const getNumericInputs = (currentInputs: Record<string, string>) => {
      const calcInputs: Record<string, number> = {};
      Object.keys(currentInputs).forEach(k => {
          const valStr = currentInputs[k].replace(',', '.');
          const val = valStr === '' || valStr === '-' ? 0 : parseFloat(valStr);
          calcInputs[k] = isNaN(val) ? 0 : val;
      });
      return calcInputs;
  };

  const evaluateExpression = (expression: string, numInputs: Record<string, number>) => {
      try {
          const names = Object.keys(numInputs);
          const values = Object.values(numInputs);
          const func = new Function(...names, `return (${expression});`);
          const res = func(...values);
          return isNaN(res) || !isFinite(res) ? 'Error' : res;
      } catch { return 'Error'; }
  };

  useEffect(() => {
    if (!isReverseMode) {
        const numInputs = getNumericInputs(inputs);
        const newResults: Record<string, string> = {};
        formula.outputs.forEach(output => {
            const res = evaluateExpression(output.expression, numInputs);
            newResults[output.id] = typeof res === 'number' ? String(Math.round(res * 10000) / 10000) : String(res);
        });
        setResults(newResults);
    }
  }, [inputs, formula.outputs, isReverseMode]);

  const solveForTarget = (targetVal: number, varSymbol: string, expression: string) => {
    let currentInputsNumeric = getNumericInputs(inputs);
    let x0 = currentInputsNumeric[varSymbol] || 1; 
    let x1 = x0 + 0.1;
    const maxIter = 50;
    const tolerance = 0.0001;
    const calc = (val: number) => {
        const temp = { ...currentInputsNumeric, [varSymbol]: val };
        const valRes = evaluateExpression(expression, temp);
        return typeof valRes === 'number' ? valRes : 0;
    };
    for (let i = 0; i < maxIter; i++) {
        const y0 = calc(x0);
        const y1 = calc(x1);
        if (Math.abs(y1 - targetVal) < tolerance) {
            setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
            return;
        }
        if (Math.abs(y1 - y0) < 1e-9) { x1 = x1 + Math.random(); continue; }
        const x_new = x1 - (y1 - targetVal) * (x1 - x0) / (y1 - y0);
        x0 = x1;
        x1 = x_new;
    }
    setInputs(prev => ({...prev, [varSymbol]: String(Math.round(x1 * 10000) / 10000)}));
  };

  const handleInputUpdate = (id: string, val: string, isOutput: boolean) => {
      if (isOutput) {
          // Goal Seek Mode
          setTargetOutputId(id);
          setResults(prev => ({...prev, [id]: val}));
          const num = parseFloat(val.replace(',', '.'));
          const targetOutput = formula.outputs.find(o => o.id === id);
          if (targetOutput && !isNaN(num) && solvingVar && val.trim() !== '' && val !== '-') {
              solveForTarget(num, solvingVar, targetOutput.expression);
          }
      } else {
          // Normal Input Mode
          setInputs(prev => ({...prev, [id]: val}));
          setTargetOutputId(null);
          // Auto-scale slider max
          if (rangeConfigs[id]?.enabled) {
              const numVal = parseFloat(val);
              if (!isNaN(numVal) && numVal > parseFloat(rangeConfigs[id].max)) {
                  setRangeConfigs(prev => ({...prev, [id]: { ...prev[id], max: val }}));
              }
          }
      }
  };

  const handleFieldFocus = (fieldId: string) => {
      setActiveField(fieldId);

      if (fieldId.startsWith('out_')) {
          setTargetOutputId(fieldId.replace('out_', ''));
      } else {
          // It is a variable input
          if (rangeConfigs[fieldId]?.enabled) {
              setShowKeyboard(false);
              return;
          }
      }

      if (!preferNativeKeyboard) {
          setShowKeyboard(true);
      } else {
          setShowKeyboard(false);
      }
  };

  // Range Config Handlers
  const handleOpenRangeConfig = (id: string, currentValue: string) => {
      setActiveRangeModalVar(id);
      const current = rangeConfigs[id];
      if (current) {
          setTempRange({ min: current.min, max: current.max });
      } else {
          const val = parseFloat(currentValue) || 0;
          setTempRange({ min: '0', max: val === 0 ? '100' : String(val * 2) });
      }
  };

  const saveRangeConfig = () => {
      if (activeRangeModalVar) {
          const minVal = parseFloat(tempRange.min);
          const maxVal = parseFloat(tempRange.max);
          if (!isNaN(minVal) && !isNaN(maxVal) && minVal < maxVal) {
              const minDec = tempRange.min.includes('.') ? tempRange.min.split('.')[1].length : 0;
              const maxDec = tempRange.max.includes('.') ? tempRange.max.split('.')[1].length : 0;
              const precision = Math.max(minDec, maxDec);
              const step = precision === 0 ? "1" : (1 / Math.pow(10, precision)).toFixed(precision);

              setRangeConfigs(prev => ({
                  ...prev,
                  [activeRangeModalVar]: {
                      min: tempRange.min,
                      max: tempRange.max,
                      enabled: true,
                      step: step,
                      precision: precision
                  }
              }));
          }
          setActiveRangeModalVar(null);
      }
  };

  const removeSlider = () => {
      if (activeRangeModalVar) {
          setRangeConfigs(prev => {
              const next = { ...prev };
              delete next[activeRangeModalVar];
              return next;
          });
          setActiveRangeModalVar(null);
      }
  };

   // --- Virtual Keyboard Logic ---
   const handleVirtualInput = (char: string) => {
      const processInput = (prev: string) => {
          if (char === 'CLEAR') return '';
          if (char === 'DEL') return prev.slice(0, -1);
          if (char === 'DONE') {
              setShowKeyboard(false);
              setPreferNativeKeyboard(true);
              return prev;
          }
          if (char === '-') {
             if (prev.startsWith('-')) return prev.slice(1);
             return '-' + prev;
          }
          let newChar = char;
          if (newChar === ',') newChar = '.';
          if (newChar === '.') {
              if (prev.includes('.') || prev.includes(',')) return prev;
              if (prev === '') return '0.';
              return prev + '.';
          }
          if (prev === '0' && !isNaN(parseInt(newChar))) return '0.' + newChar;
          return prev + newChar;
      };

      if (!activeField) return;

      if (activeField.startsWith('out_')) {
          const outId = activeField.replace('out_', '');
          const currentVal = results[outId] || '';
          handleInputUpdate(outId, processInput(currentVal), true);
      } else {
          const currentVal = inputs[activeField] || '';
          handleInputUpdate(activeField, processInput(currentVal), false);
      }
  };

  const handleForceShowKeyboard = () => {
      setPreferNativeKeyboard(false);
      setShowKeyboard(true);
  };

  return (
    <div className={`flex flex-col h-screen bg-${theme}-950 font-sans`}>

      {/* Header */}
      <div className={`flex items-center justify-center px-4 bg-${theme}-950 shrink-0 ${uiConfig.headerHeightClass} z-20 sticky top-0 border-b border-${theme}-900 relative`}>
          <div className="absolute left-4 flex gap-2">
            <button onClick={onOpenDevTools} className={`p-2 text-${theme}-600 hover:text-white transition-colors`}><Wrench className={uiConfig.iconClassName} /></button>
            <button onClick={onOpenSettings} className={`p-2 text-${theme}-600 hover:text-white transition-colors`}><Settings className={uiConfig.iconClassName} /></button>
          </div>
          <h1 className={`text-white font-bold ${uiConfig.headerClassName} truncate font-mono tracking-widest uppercase`}>{formula.title}</h1>
          <button onClick={() => {}} className={`absolute right-4 p-2 transition-all rounded-full text-${theme}-600 hover:text-red-400 hover:bg-${theme}-900`}>
              <X className={uiConfig.iconClassName} onClick={onBack} />
          </button>
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 overflow-y-auto p-4 transition-all duration-300 ${showKeyboard ? 'pb-80' : 'pb-24'}`}>

          {/* Goal Seek (Permanent Bar) */}
          {formula.variables.length > 0 && (
             <div 
                className={`mb-6 h-12 px-4 rounded-[1.5rem] flex items-center justify-between transition-all duration-300 
                ${isReverseMode 
                    ? 'bg-indigo-600 text-white shadow-lg' 
                    : `bg-${theme}-900/40 text-${theme}-600 opacity-60 pointer-events-none`}`}
             >
                 <div className="flex items-center gap-2">
                    <ArrowRightLeft className="w-4 h-4" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Target Var:</span>
                 </div>
                 <select 
                    value={solvingVar}
                    onChange={(e) => setSolvingVar(e.target.value)}
                    className={`bg-transparent text-sm font-bold uppercase outline-none text-right appearance-none pointer-events-auto`}
                    disabled={!isReverseMode}
                 >
                    {formula.variables.map(v => (
                        <option key={v.symbol} value={v.symbol} className="text-black">{v.name || v.symbol}</option>
                    ))}
                 </select>
             </div>
          )}

          {/* Results Section */}
          <div className="mb-8 space-y-4">
              <div className="flex items-center gap-3 px-2 mb-2">
                  <span className={`text-[10px] font-bold text-indigo-400 uppercase tracking-[0.2em]`}>Outputs</span>
                  <div className="h-px flex-1 bg-indigo-900/50"></div>
              </div>
              {formula.outputs.map((output) => (
                  <RunnerTile 
                      key={output.id}
                      id={output.id}
                      label={output.name || "RESULT"}
                      value={results[output.id] || ''}
                      unit={output.unit}
                      isResult={true}
                      isActive={activeField === `out_${output.id}`}
                      rangeConfig={rangeConfigs[output.id]}
                      theme={theme}
                      uiConfig={uiConfig}
                      onValueChange={(val) => handleInputUpdate(output.id, val, true)}
                      onFocus={() => { setActiveField(`out_${output.id}`); setTargetOutputId(output.id); }}
                      onToggleSliderConfig={() => handleOpenRangeConfig(output.id, results[output.id] || '0')}
                      onReset={() => handleInputUpdate(output.id, '0', true)}
                  />
              ))}
          </div>

          {/* Variables Section */}
          <div className="space-y-4">
              <div className="flex items-center gap-3 px-2 mb-2">
                   <span className={`text-[10px] font-bold text-${theme}-500 uppercase tracking-[0.2em]`}>Inputs</span>
                   <div className={`h-px flex-1 bg-${theme}-900`}></div>
              </div>
              {formula.variables.map((v) => (
                  <RunnerTile 
                      key={v.id}
                      id={v.symbol}
                      label={v.name || v.symbol}
                      value={inputs[v.symbol] || ''}
                      unit={v.unit}
                      isResult={false}
                      isActive={activeField === v.symbol}
                      rangeConfig={rangeConfigs[v.symbol]}
                      theme={theme}
                      uiConfig={uiConfig}
                      onValueChange={(val) => handleInputUpdate(v.symbol, val, false)}
                      onFocus={() => { setActiveField(v.symbol); }}
                      onToggleSliderConfig={() => handleOpenRangeConfig(v.symbol, inputs[v.symbol] || '0')}
                      onReset={() => handleInputUpdate(v.symbol, '0', false)}
                  />
              ))}
          </div>

          {/* Info Panel (Toggled) */}
          {showInfo && (
            <div className={`mt-8 bg-${theme}-900/50 rounded-2xl p-6 animate-fade-in`}>
                <p className={`text-${theme}-300 italic mb-4 leading-relaxed`}>{formula.description || "No description provided."}</p>
                <div className="space-y-2">
                    {formula.outputs.map((o, i) => (
                         <div key={i} className={`text-xs font-mono text-${theme}-500`}>
                             <span className="text-indigo-400 font-bold">{o.name}:</span> {o.expression}
                         </div>
                    ))}
                </div>
            </div>
          )}
      </div>

      {/* Footer Controls (Restored) */}
      <div className={`bg-${theme}-950 border-t border-${theme}-900 p-0 z-30 flex ${uiConfig.headerHeightClass} safe-area-pb`}>
            <button 
                onClick={onBack}
                className={`flex-1 flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}
            >
                <ArrowLeft className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={onEdit} 
                className={`flex-1 flex justify-center items-center text-${theme}-500 hover:text-white hover:bg-${theme}-900 transition-colors border-r border-${theme}-900`}
            >
                <Edit2 className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={() => setShowInfo(!showInfo)} 
                className={`flex-1 flex justify-center items-center transition-colors border-r border-${theme}-900 ${showInfo ? `bg-${theme}-900 text-white` : `text-${theme}-500 hover:text-white hover:bg-${theme}-900`}`}
            >
                <Info className={uiConfig.iconClassName} />
            </button>

            <button 
                onClick={showKeyboard ? () => { setShowKeyboard(false); setPreferNativeKeyboard(true); } : handleForceShowKeyboard}
                className={`flex-1 flex justify-center items-center transition-all active:bg-${theme}-900 ${showKeyboard ? 'bg-blue-600 text-white' : `text-${theme}-500 hover:text-white hover:bg-${theme}-900`}`}
            >
                {showKeyboard ? <ChevronDown className={uiConfig.iconClassName} /> : <Keyboard className={uiConfig.iconClassName} />}
            </button>
      </div>

      {/* Range Config Modal */}
      {activeRangeModalVar && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-sm animate-fade-in p-0">
              <div className={`bg-${theme}-950 w-full max-w-xs shadow-2xl border border-${theme}-900 rounded-xl overflow-hidden`}>
                  <div className={`h-12 flex items-center px-4 border-b border-${theme}-900 bg-${theme}-900/30`}>
                    <h3 className={`text-white text-xs font-bold font-mono uppercase tracking-widest`}>
                        Slider Config
                    </h3>
                  </div>
                  <div className="p-4">
                      <div className="flex gap-3 mb-4">
                          <div className="flex-1">
                              <label className={`text-[10px] uppercase text-${theme}-500 font-bold mb-1 block tracking-widest`}>Min</label>
                              <input 
                                  type="text"
                                  inputMode="decimal"
                                  value={tempRange.min} 
                                  onChange={e => setTempRange(prev => ({...prev, min: e.target.value}))}
                                  className={`w-full bg-${theme}-900/50 p-2 text-white text-sm font-mono outline-none rounded border border-transparent focus:border-blue-500`}
                              />
                          </div>
                          <div className="flex-1">
                              <label className={`text-[10px] uppercase text-${theme}-500 font-bold mb-1 block tracking-widest`}>Max</label>
                              <input 
                                  type="text"
                                  inputMode="decimal"
                                  value={tempRange.max} 
                                  onChange={e => setTempRange(prev => ({...prev, max: e.target.value}))}
                                  className={`w-full bg-${theme}-900/50 p-2 text-white text-sm font-mono outline-none rounded border border-transparent focus:border-blue-500`}
                              />
                          </div>
                      </div>
                      <div className={`flex gap-2`}>
                          {rangeConfigs[activeRangeModalVar] && (
                               <button onClick={removeSlider} className={`px-4 bg-red-900/30 text-red-500 hover:text-white hover:bg-red-900 rounded font-bold uppercase text-xs`}>
                                   Disable
                               </button>
                          )}
                          <button onClick={() => setActiveRangeModalVar(null)} className={`flex-1 py-3 bg-${theme}-900 text-${theme}-400 hover:text-white font-bold uppercase text-xs tracking-widest rounded`}>Cancel</button>
                          <button onClick={saveRangeConfig} className={`flex-1 py-3 bg-blue-600 text-white hover:bg-blue-500 font-bold uppercase text-xs tracking-widest rounded`}>Save</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Virtual Keyboard Overlay */}
      <div className={`fixed bottom-0 left-0 right-0 bg-${theme}-950 z-[60] transition-transform duration-200 ease-out pb-safe border-t border-${theme}-900 ${showKeyboard ? 'translate-y-0' : 'translate-y-full'}`}>
          <div className={`flex justify-center items-center h-10 bg-${theme}-950 border-b border-${theme}-900`}>
              <button onClick={() => setShowKeyboard(false)} className={`w-full h-full flex items-center justify-center text-${theme}-500 active:text-white`}>
                  <ChevronDown className={uiConfig.iconClassName} />
              </button>
          </div>
          <div className="grid grid-cols-4 gap-px bg-${theme}-900">
              {[1, 2, 3].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
               <button onClick={() => handleVirtualInput('DEL')} className={`h-[55px] bg-${theme}-950 text-xl font-medium text-red-500 active:bg-${theme}-900 flex items-center justify-center touch-none hover:bg-${theme}-900 transition-colors`}><Delete className="w-6 h-6" /></button>

              {[4, 5, 6].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
              <button onClick={() => handleVirtualInput('-')} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 flex items-center justify-center hover:bg-${theme}-900 transition-colors`}><Minus className="w-6 h-6" /></button>

              {[7, 8, 9].map(num => (
                  <button key={num} onClick={() => handleVirtualInput(String(num))} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>{num}</button>
              ))}
              <button onClick={() => handleVirtualInput('.')} className={`h-[55px] bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>.</button>

              <div className="col-span-2">
                  <button onClick={() => handleVirtualInput('0')} className={`h-[55px] w-full bg-${theme}-950 text-2xl font-mono text-white active:bg-${theme}-900 hover:bg-${theme}-900 transition-colors`}>0</button>
              </div>
              <div className="col-span-2">
                   <button onClick={() => handleVirtualInput('DONE')} className={`h-[55px] w-full bg-blue-600 text-white font-bold ${uiConfig.bodyClassName} uppercase tracking-widest active:bg-blue-500 flex items-center justify-center transition-colors`}>DONE</button>
              </div>
          </div>
      </div>
    </div>
  );
};

