// --- Migration Helper ---
const migrateFormula = (f: Formula): Formula => {
    // If outputs don't exist but expression does, migrate it
    if ((!f.outputs || f.outputs.length === 0) && f.expression) {
        return {
            ...f,
            outputs: [{
                id: 'default_output',
                name: f.resultName || 'Result',
                unit: f.resultUnit || '',
                expression: f.expression
            }]
        };
    }
    return f;
}

